import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { redirectToLogin } from "@/services/auth";
import { useAuth } from "@/lib/AuthContext";
import { filterNavForRole, PUBLIC_PAGES } from "@/lib/rbac";
import { useModuleAccess } from "@/lib/ModuleAccessContext";
import { filterNavForModules } from "@/lib/moduleConfig";
import {
  Building2, LayoutDashboard, Briefcase, Home, FileText,
  DollarSign, Calculator, TrendingUp, ClipboardCheck, BarChart3,
  Bell, Shield, ChevronRight, LogOut, Menu, X,
  Users, Receipt, GitBranch, FolderOpen, Plug,
  Search, User, Layers, ArrowLeftRight
} from "lucide-react";
import { Input } from "@/components/ui/input";

const publicPages = PUBLIC_PAGES;

const navSections = [
  { label: "Dashboard", icon: LayoutDashboard, page: "Dashboard" },
  { label: "Portfolio", icon: Briefcase, page: "Portfolios" },
  {
    label: "Properties", icon: Home, children: [
      { label: "All Properties", page: "Properties" },
      { label: "Buildings & Units", page: "BuildingsUnits" },
    ]
  },
  {
    label: "Tenants", icon: Users, children: [
      { label: "All Tenants", page: "Tenants" },
      { label: "Billing", page: "Billing" },
    ]
  },
  {
    label: "Leases", icon: FileText, children: [
      { label: "Lease List", page: "Leases" },
      { label: "Upload Lease", page: "LeaseUpload" },
      { label: "Lease Review", page: "LeaseReview" },
      { label: "Rent Projection", page: "RentProjection" },
    ]
  },
  {
    label: "Expenses", icon: Receipt, children: [
      { label: "Expense Dashboard", page: "Expenses" },
      { label: "Add Expense", page: "AddExpense" },
      { label: "Bulk Import", page: "BulkImport" },
      { label: "Expense Projection", page: "ExpenseProjection" },
      { label: "Vendors", page: "Vendors" },
    ]
  },
  {
    label: "CAM Engine", icon: Calculator, children: [
      { label: "CAM Dashboard", page: "CAMDashboard" },
      { label: "CAM Calculation", page: "CAMCalculation" },
    ]
  },
  { label: "Revenue", icon: TrendingUp, page: "Revenue" },
  {
    label: "Budget Studio", icon: ClipboardCheck, children: [
      { label: "Budget Dashboard", page: "BudgetDashboard" },
      { label: "Create Budget", page: "CreateBudget" },
      { label: "Budget Review", page: "BudgetReview" },
    ]
  },
  { label: "Actuals & Variance", icon: Layers, page: "ActualsVariance" },
  { label: "YoY Comparison", icon: ArrowLeftRight, page: "Comparison" },
  { label: "Reconciliation", icon: DollarSign, page: "Reconciliation" },
  { label: "Analytics & Reports", icon: BarChart3, page: "AnalyticsReports" },
  { label: "Workflows", icon: GitBranch, page: "Workflows" },
  { label: "Notifications", icon: Bell, page: "Notifications" },
  { label: "Documents", icon: FolderOpen, page: "Documents" },
  { label: "Integrations", icon: Plug, page: "Integrations" },
  {
    label: "Settings", icon: Shield, children: [
      { label: "User Management", page: "UserManagement" },
      { label: "Org Settings", page: "OrgSettings" },
      { label: "Chart of Accounts", page: "ChartOfAccounts" },
      { label: "Audit Log", page: "AuditLog" },
    ]
  },
  {
    label: "Platform", icon: Layers, children: [
      { label: "Organizations", page: "SuperAdmin" },
      { label: "Stakeholders", page: "Stakeholders" },
    ]
  },
];

function NavItem({ item, currentPageName, collapsed }) {
  const [open, setOpen] = useState(false);
  const isActive = item.page === currentPageName || item.children?.some(c => c.page === currentPageName);

  useEffect(() => {
    if (isActive && item.children) setOpen(true);
  }, [isActive]);

  if (item.children) {
    return (
      <div>
        <button
          onClick={() => setOpen(!open)}
          className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${isActive ? 'text-white bg-white/10' : 'text-white/60 hover:text-white hover:bg-white/5'}`}
        >
          <item.icon className="w-[18px] h-[18px] flex-shrink-0" />
          {!collapsed && (
            <>
              <span className="flex-1 text-left">{item.label}</span>
              <ChevronRight className={`w-3.5 h-3.5 transition-transform ${open ? 'rotate-90' : ''}`} />
            </>
          )}
        </button>
        {open && !collapsed && (
          <div className="ml-8 mt-1 space-y-0.5">
            {item.children.map(child => (
              <Link
                key={child.page}
                to={createPageUrl(child.page)}
                className={`block px-3 py-1.5 rounded-md text-[13px] transition-colors ${child.page === currentPageName ? 'text-white bg-white/10' : 'text-white/50 hover:text-white hover:bg-white/5'}`}
              >
                {child.label}
              </Link>
            ))}
          </div>
        )}
      </div>
    );
  }

  return (
    <Link
      to={createPageUrl(item.page)}
      className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${isActive ? 'text-white bg-white/10' : 'text-white/60 hover:text-white hover:bg-white/5'}`}
    >
      <item.icon className="w-[18px] h-[18px] flex-shrink-0" />
      {!collapsed && <span>{item.label}</span>}
    </Link>
  );
}

export default function Layout({ children, currentPageName }) {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [mobileOpen, setMobileOpen] = useState(false);
  const navigate = useNavigate();
  const { user, logout: authContextLogout } = useAuth();
  const { enabledModules } = useModuleAccess();

  // Handle unauthenticated state if on a protected page
  useEffect(() => {
    if (!user) {
      if (!publicPages.includes(currentPageName)) {
        redirectToLogin(window.location.href);
      }
    }
  }, [user, currentPageName]);

  if (publicPages.includes(currentPageName) || currentPageName === "Onboarding" || currentPageName === "Landing") {
    return <>{children}</>;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className={`hidden lg:flex flex-col bg-[#1a2744] transition-all duration-300 ${sidebarOpen ? 'w-[250px]' : 'w-[68px]'} flex-shrink-0`}>
        <div className="h-14 flex items-center gap-2.5 px-4 border-b border-white/10">
          <div className="w-8 h-8 bg-gradient-to-br from-blue-400 to-blue-600 rounded-lg flex items-center justify-center flex-shrink-0 shadow-md">
            <Building2 className="w-4.5 h-4.5 text-white" />
          </div>
          {sidebarOpen && (
            <div className="min-w-0">
              <div className="text-white font-bold text-sm leading-tight truncate">CRE PLATFORM</div>
              <div className="text-blue-300/50 text-[9px] font-semibold tracking-[0.1em]">BUDGETING & CAM</div>
            </div>
          )}
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="ml-auto text-white/40 hover:text-white transition-colors">
            {sidebarOpen ? <X className="w-4 h-4" /> : <Menu className="w-4 h-4" />}
          </button>
        </div>

        <nav className="flex-1 overflow-y-auto px-3 py-3 space-y-0.5">
          {filterNavForModules(filterNavForRole(navSections, user?.role), enabledModules).map((item, i) => (
            <NavItem key={i} item={item} currentPageName={currentPageName} collapsed={!sidebarOpen} />
          ))}
        </nav>

        {sidebarOpen && (
          <div className="p-3 border-t border-white/10">
            <div className="flex items-center gap-3 px-2">
              <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-white text-xs font-bold">
                <User className="w-4 h-4" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-white text-sm font-medium truncate">{user?.full_name || "User"}</p>
                <p className="text-white/40 text-xs truncate capitalize">{user?.role === "admin" ? "SuperAdmin" : (user?.role || "User").replace("_", " ")}</p>
              </div>
              <button onClick={() => authContextLogout(true)} className="text-white/30 hover:text-white" title="Logout">
                <LogOut className="w-4 h-4" />
              </button>
            </div>
          </div>
        )}
      </aside>

      {/* Mobile sidebar */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 z-50">
          <div className="absolute inset-0 bg-black/50" onClick={() => setMobileOpen(false)} />
          <aside className="relative w-[250px] h-full bg-[#1a2744] flex flex-col">
            <div className="h-14 flex items-center gap-2.5 px-4 border-b border-white/10">
              <Building2 className="w-5 h-5 text-white" />
              <span className="text-white font-bold text-sm">NEXUS CRE</span>
              <button onClick={() => setMobileOpen(false)} className="ml-auto text-white/40"><X className="w-5 h-5" /></button>
            </div>
            <nav className="flex-1 overflow-y-auto px-3 py-3 space-y-0.5">
              {filterNavForModules(filterNavForRole(navSections, user?.role), enabledModules).map((item, i) => (
                <NavItem key={i} item={item} currentPageName={currentPageName} collapsed={false} />
              ))}
            </nav>
          </aside>
        </div>
      )}

      {/* Main content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-14 bg-white border-b border-slate-200 flex items-center justify-between px-6 flex-shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setMobileOpen(true)} className="lg:hidden text-slate-600"><Menu className="w-5 h-5" /></button>
            <div className="text-sm text-slate-500">
              <span className="font-semibold text-slate-700">{currentPageName}</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <div className="relative hidden md:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <Input placeholder="Search..." className="pl-9 w-56 h-9 bg-slate-50 border-slate-200 text-sm" />
            </div>
            <Link to={createPageUrl("Notifications")} className="relative p-2 hover:bg-slate-100 rounded-lg">
              <Bell className="w-5 h-5 text-slate-500" />
              <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white" />
            </Link>
            <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-white text-xs font-bold">
              <User className="w-4 h-4" />
            </div>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto">{children}</main>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

function fmt(v) {
  if (!v && v !== 0) return "$0";
  const abs = Math.abs(v);
  const sign = v < 0 ? "-" : "";
  if (abs >= 1e6) return `${sign}$${(abs / 1e6).toFixed(2)}M`;
  if (abs >= 1e3) return `${sign}$${(abs / 1e3).toFixed(1)}K`;
  return `${sign}$${abs.toLocaleString()}`;
}

const DEFAULT_SCENARIOS = {
  base: { label: "Base", color: "bg-blue-100 text-blue-700", occupancyAdj: 0, rentAdj: 0, expenseAdj: 0 },
  optimistic: { label: "Optimistic", color: "bg-emerald-100 text-emerald-700", occupancyAdj: 5, rentAdj: 3, expenseAdj: -2 },
  conservative: { label: "Conservative", color: "bg-amber-100 text-amber-700", occupancyAdj: -10, rentAdj: -2, expenseAdj: 5 },
};

export default function ScenarioPlanner({ baseRevenue = 0, baseExpenses = 0, baseOccupancy = 0, baseRentPerSF = 0, totalSF = 0 }) {
  const [scenarios, setScenarios] = useState(DEFAULT_SCENARIOS);

  const updateScenario = (key, field, value) => {
    setScenarios(prev => ({ ...prev, [key]: { ...prev[key], [field]: parseFloat(value) || 0 } }));
  };

  const calcScenario = (s) => {
    const adjOcc = Math.min(100, Math.max(0, baseOccupancy + s.occupancyAdj));
    const adjLeasedSF = totalSF * (adjOcc / 100);
    const adjRentPerSF = baseRentPerSF * (1 + s.rentAdj / 100);
    const adjRevenue = adjLeasedSF * adjRentPerSF + (baseRevenue - baseRentPerSF * totalSF * (baseOccupancy / 100));
    const effectiveRevenue = baseRevenue > 0 ? baseRevenue * (1 + s.rentAdj / 100) * ((baseOccupancy + s.occupancyAdj) / Math.max(baseOccupancy, 1)) : 0;
    const adjExpenses = baseExpenses * (1 + s.expenseAdj / 100);
    const noi = effectiveRevenue - adjExpenses;
    const baseNOI = baseRevenue - baseExpenses;
    const noiDiff = noi - baseNOI;
    const revChange = baseRevenue > 0 ? ((effectiveRevenue - baseRevenue) / baseRevenue * 100) : 0;
    return { revenue: effectiveRevenue, expenses: adjExpenses, noi, noiDiff, revChange, occupancy: baseOccupancy + s.occupancyAdj };
  };

  return (
    <Card className="border-0 shadow-sm">
      <CardHeader className="pb-2 pt-4 px-4">
        <CardTitle className="text-sm font-bold text-slate-900">Scenario Planning</CardTitle>
        <p className="text-[10px] text-slate-500">Adjust occupancy, rent, and expenses to compare outcomes</p>
      </CardHeader>
      <CardContent className="px-4 pb-4">
        <Tabs defaultValue="base">
          <TabsList className="bg-slate-100 h-8">
            {Object.entries(scenarios).map(([key, s]) => (
              <TabsTrigger key={key} value={key} className="text-xs h-6 data-[state=active]:bg-white">
                <Badge className={`${s.color} text-[9px] mr-1`}>{s.label}</Badge>
              </TabsTrigger>
            ))}
          </TabsList>

          {Object.entries(scenarios).map(([key, s]) => {
            const calc = calcScenario(s);
            return (
              <TabsContent key={key} value={key} className="mt-3 space-y-3">
                <div className="grid grid-cols-3 gap-3">
                  <div>
                    <Label className="text-[10px] text-slate-500">Occupancy Adj (%)</Label>
                    <Input type="number" value={s.occupancyAdj} onChange={e => updateScenario(key, 'occupancyAdj', e.target.value)} className="h-8 text-sm" disabled={key === 'base'} />
                  </div>
                  <div>
                    <Label className="text-[10px] text-slate-500">Rent Change (%)</Label>
                    <Input type="number" value={s.rentAdj} onChange={e => updateScenario(key, 'rentAdj', e.target.value)} className="h-8 text-sm" disabled={key === 'base'} />
                  </div>
                  <div>
                    <Label className="text-[10px] text-slate-500">Expense Change (%)</Label>
                    <Input type="number" value={s.expenseAdj} onChange={e => updateScenario(key, 'expenseAdj', e.target.value)} className="h-8 text-sm" disabled={key === 'base'} />
                  </div>
                </div>

                <div className="grid grid-cols-4 gap-2">
                  {[
                    { label: "Revenue", value: calc.revenue, base: baseRevenue },
                    { label: "Expenses", value: calc.expenses, base: baseExpenses },
                    { label: "NOI", value: calc.noi, base: baseRevenue - baseExpenses },
                    { label: "Occupancy", value: `${calc.occupancy.toFixed(0)}%`, base: null },
                  ].map((m, i) => {
                    const diff = m.base !== null ? ((typeof m.value === 'number' ? m.value : 0) - m.base) : 0;
                    return (
                      <div key={i} className="bg-slate-50 rounded-lg p-2.5 text-center">
                        <p className="text-[9px] text-slate-500 uppercase font-semibold">{m.label}</p>
                        <p className="text-sm font-bold text-slate-900 tabular-nums">{typeof m.value === 'number' ? fmt(m.value) : m.value}</p>
                        {m.base !== null && key !== 'base' && (
                          <div className={`text-[9px] font-bold ${diff > 0 ? 'text-emerald-600' : diff < 0 ? 'text-red-600' : 'text-slate-400'}`}>
                            {diff > 0 ? '+' : ''}{fmt(diff)}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                {key !== 'base' && (
                  <div className="flex items-center gap-4 bg-slate-50 rounded-lg p-2.5 text-xs">
                    <div className="flex items-center gap-1">
                      <span className="text-slate-500">NOI Δ:</span>
                      <span className={`font-bold ${calc.noiDiff >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>{calc.noiDiff >= 0 ? '+' : ''}{fmt(calc.noiDiff)}</span>
                    </div>
                    <div className="flex items-center gap-1">
                      <span className="text-slate-500">Revenue Δ:</span>
                      <span className={`font-bold ${calc.revChange >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>{calc.revChange >= 0 ? '+' : ''}{calc.revChange.toFixed(1)}%</span>
                    </div>
                  </div>
                )}
              </TabsContent>
            );
          })}
        </Tabs>
      </CardContent>
    </Card>
  );
}

import React, { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Minus, AlertTriangle, ChevronDown, ChevronUp, ArrowUpRight, ArrowDownRight } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend, PieChart, Pie, Cell } from "recharts";

function analyzeIncreaseReasons(currCAMs, prevCAMs, expenses) {
  const reasons = [];
  const currPool = currCAMs.reduce((s, c) => s + (c.total_cam_pool || 0), 0);
  const prevPool = prevCAMs.reduce((s, c) => s + (c.total_cam_pool || 0), 0);

  if (prevPool > 0 && currPool > prevPool) {
    const poolDelta = currPool - prevPool;
    const poolPct = ((poolDelta / prevPool) * 100).toFixed(1);
    reasons.push({ label: "Total CAM Pool Increase", detail: `+$${poolDelta.toLocaleString()} (+${poolPct}%)`, severity: poolPct > 10 ? "high" : poolPct > 5 ? "medium" : "low" });
  }

  // Admin fee changes
  const currAdminFees = currCAMs.reduce((s, c) => s + (c.admin_fee || 0), 0);
  const prevAdminFees = prevCAMs.reduce((s, c) => s + (c.admin_fee || 0), 0);
  if (prevAdminFees > 0 && currAdminFees > prevAdminFees * 1.05) {
    reasons.push({ label: "Admin Fee Increase", detail: `$${prevAdminFees.toLocaleString()} → $${currAdminFees.toLocaleString()}`, severity: "medium" });
  }

  // Gross-up changes
  const currGrossUp = currCAMs.reduce((s, c) => s + (c.gross_up_adjustment || 0), 0);
  const prevGrossUp = prevCAMs.reduce((s, c) => s + (c.gross_up_adjustment || 0), 0);
  if (currGrossUp > prevGrossUp && prevGrossUp >= 0) {
    reasons.push({ label: "Gross-Up Adjustment", detail: `+$${(currGrossUp - prevGrossUp).toLocaleString()} (vacancy adjustment)`, severity: "medium" });
  }

  // Controllable vs non-controllable
  const currCtrl = currCAMs.reduce((s, c) => s + (c.controllable_total || 0), 0);
  const prevCtrl = prevCAMs.reduce((s, c) => s + (c.controllable_total || 0), 0);
  const currNonCtrl = currCAMs.reduce((s, c) => s + (c.non_controllable_total || 0), 0);
  const prevNonCtrl = prevCAMs.reduce((s, c) => s + (c.non_controllable_total || 0), 0);

  if (prevCtrl > 0 && currCtrl > prevCtrl * 1.05) {
    reasons.push({ label: "Controllable Expenses Up", detail: `+$${(currCtrl - prevCtrl).toLocaleString()} (+${((currCtrl - prevCtrl) / prevCtrl * 100).toFixed(0)}%)`, severity: "medium" });
  }
  if (prevNonCtrl > 0 && currNonCtrl > prevNonCtrl * 1.05) {
    reasons.push({ label: "Non-Controllable Expenses Up", detail: `+$${(currNonCtrl - prevNonCtrl).toLocaleString()} (taxes/insurance/utilities)`, severity: "high" });
  }

  // Expense category analysis
  const currentYear = new Date().getFullYear();
  const currYearExp = expenses.filter(e => e.fiscal_year === currentYear && e.classification === 'recoverable');
  const prevYearExp = expenses.filter(e => e.fiscal_year === currentYear - 1 && e.classification === 'recoverable');
  const currCats = {};
  const prevCats = {};
  currYearExp.forEach(e => { currCats[e.category] = (currCats[e.category] || 0) + (e.amount || 0); });
  prevYearExp.forEach(e => { prevCats[e.category] = (prevCats[e.category] || 0) + (e.amount || 0); });

  Object.keys(currCats).forEach(cat => {
    const curr = currCats[cat];
    const prev = prevCats[cat] || 0;
    if (prev > 0 && curr > prev * 1.15) {
      reasons.push({ label: `${cat.replace(/_/g, ' ')} Expense Spike`, detail: `$${prev.toLocaleString()} → $${curr.toLocaleString()} (+${((curr - prev) / prev * 100).toFixed(0)}%)`, severity: "medium" });
    } else if (curr > 0 && prev === 0) {
      reasons.push({ label: `New: ${cat.replace(/_/g, ' ')}`, detail: `$${curr.toLocaleString()} (new category)`, severity: "low" });
    }
  });

  return reasons;
}

export default function CAMReviewTab({ camCalcs, expenses, leases, currentYear, prevYear, scopeProperty }) {
  const [expandedTenant, setExpandedTenant] = useState(null);

  const scopedCAMs = scopeProperty !== "all" ? camCalcs.filter(c => c.property_id === scopeProperty) : camCalcs;
  const currCAMs = scopedCAMs.filter(c => c.fiscal_year === currentYear);
  const prevCAMs = scopedCAMs.filter(c => c.fiscal_year === prevYear);
  const scopedExpenses = scopeProperty !== "all" ? expenses.filter(e => e.property_id === scopeProperty) : expenses;

  const currTotal = currCAMs.reduce((s, c) => s + (c.annual_cam || 0), 0);
  const prevTotal = prevCAMs.reduce((s, c) => s + (c.annual_cam || 0), 0);
  const totalDelta = currTotal - prevTotal;
  const totalPct = prevTotal > 0 ? (totalDelta / prevTotal * 100).toFixed(1) : null;

  const currPool = currCAMs.reduce((s, c) => s + (c.total_cam_pool || 0), 0);
  const prevPool = prevCAMs.reduce((s, c) => s + (c.total_cam_pool || 0), 0);
  const currAdminFees = currCAMs.reduce((s, c) => s + (c.admin_fee || 0), 0);
  const currGrossUp = currCAMs.reduce((s, c) => s + (c.gross_up_adjustment || 0), 0);

  // Increase reasons
  const reasons = analyzeIncreaseReasons(currCAMs, prevCAMs, scopedExpenses);
  const sevColors = { high: "bg-red-100 text-red-700 border-red-200", medium: "bg-amber-100 text-amber-700 border-amber-200", low: "bg-blue-100 text-blue-700 border-blue-200" };

  // Tenant-level comparison
  const tenantData = currCAMs.map(curr => {
    const prev = prevCAMs.find(p => p.lease_id === curr.lease_id || p.tenant_name === curr.tenant_name);
    const prevAnnual = prev?.annual_cam || 0;
    const delta = (curr.annual_cam || 0) - prevAnnual;
    const pct = prevAnnual > 0 ? (delta / prevAnnual * 100) : null;
    const lease = leases.find(l => l.id === curr.lease_id);
    return {
      ...curr, prevAnnual, delta, pct, capApplied: curr.cap_applied,
      leaseType: lease?.lease_type, totalSF: lease?.total_sf || curr.tenant_share_pct
    };
  }).sort((a, b) => Math.abs(b.delta) - Math.abs(a.delta));

  // Chart data - top tenants
  const chartData = tenantData.slice(0, 8).map(t => ({
    name: (t.tenant_name || "Unknown").substring(0, 14),
