import React, { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Building2, Layers, Users, ChevronRight } from "lucide-react";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";
import RevenueSourcePopover from "./RevenueSourcePopover";
import TenantDrillDown from "./TenantDrillDown";

const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const COLORS = ["#1a2744","#2563eb","#10b981","#f59e0b","#8b5cf6","#ef4444","#06b6d4"];

function fmt(v) {
  if (v >= 1e6) return `$${(v / 1e6).toFixed(2)}M`;
  if (v >= 1e3) return `$${(v / 1e3).toFixed(1)}K`;
  return `$${v.toLocaleString()}`;
}

function MonthlyTrendChart({ leases, camCalcs }) {
  const rent = leases.reduce((s, l) => s + (l.base_rent || 0), 0);
  const cam = camCalcs.reduce((s, c) => s + (c.monthly_cam || 0), 0);
  const data = MONTHS.map(m => ({ month: m, "Base Rent": rent, "CAM Recovery": cam }));

  return (
    <Card>
      <CardHeader className="pb-2"><CardTitle className="text-sm">Monthly Revenue Trend</CardTitle></CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={220}>
          <AreaChart data={data}>
            <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
            <XAxis dataKey="month" tick={{ fontSize: 10 }} />
            <YAxis tick={{ fontSize: 10 }} tickFormatter={v => `$${(v / 1000).toFixed(0)}K`} />
            <Tooltip formatter={v => `$${v.toLocaleString()}`} />
            <Legend wrapperStyle={{ fontSize: 11 }} />
            <Area type="monotone" dataKey="Base Rent" stackId="1" stroke="#1a2744" fill="#1a2744" fillOpacity={0.12} strokeWidth={2} />
            <Area type="monotone" dataKey="CAM Recovery" stackId="1" stroke="#3b82f6" fill="#3b82f6" fillOpacity={0.1} strokeWidth={2} />
          </AreaChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
}

function BreakdownSection({ icon: Icon, title, data, columns, onRowClick }) {
  return (
    <Card>
      <CardHeader className="pb-2">
        <div className="flex items-center gap-2">
          <Icon className="w-4 h-4 text-slate-500" />
          <CardTitle className="text-sm">{title}</CardTitle>
          <Badge variant="outline" className="text-[10px] ml-auto">{data.length}</Badge>
        </div>
      </CardHeader>
      <CardContent className="p-0">
        <Table>
          <TableHeader>
            <TableRow className="bg-slate-50/80">
              {columns.map(c => (
                <TableHead key={c.key} className={`text-[10px] font-semibold uppercase tracking-wider ${c.align === 'right' ? 'text-right' : ''}`}>{c.label}</TableHead>
              ))}
              {onRowClick && <TableHead className="w-6"></TableHead>}
            </TableRow>
          </TableHeader>
          <TableBody>
            {data.length === 0 ? (
              <TableRow><TableCell colSpan={columns.length + (onRowClick ? 1 : 0)} className="text-center py-8 text-sm text-slate-400">No data</TableCell></TableRow>
            ) : (
              data.map((row, i) => (
                <TableRow key={i} className={onRowClick ? "cursor-pointer hover:bg-blue-50/50 group" : ""} onClick={() => onRowClick?.(row)}>
                  {columns.map(c => (
                    <TableCell key={c.key} className={`text-sm ${c.align === 'right' ? 'text-right font-mono' : ''} ${c.bold ? 'font-semibold' : ''}`}>
                      {c.render ? c.render(row) : row[c.key]}
                    </TableCell>
                  ))}
                  {onRowClick && <TableCell><ChevronRight className="w-3.5 h-3.5 text-slate-300 group-hover:text-blue-600" /></TableCell>}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}

export default function PropertyDrillDown({ property, leases, camCalcs, buildings, units, onBack }) {
  const [selectedTenant, setSelectedTenant] = useState(null);

  const propLeases = leases.filter(l => l.property_id === property.id && l.status !== 'expired');
  const propCams = camCalcs.filter(c => c.property_id === property.id);

  const totalRent = propLeases.reduce((s, l) => s + (l.annual_rent || l.base_rent * 12 || 0), 0);
  const totalCam = propCams.reduce((s, c) => s + (c.annual_cam || 0), 0);
  const totalRevenue = totalRent + totalCam;

  // Building breakdown
  const propBuildings = buildings.filter(b => b.property_id === property.id);
  const buildingData = propBuildings.map(b => {
    const bUnits = units.filter(u => u.building_id === b.id);
    const bLeases = propLeases.filter(l => bUnits.some(u => u.id === l.unit_id));
    const rent = bLeases.reduce((s, l) => s + (l.annual_rent || l.base_rent * 12 || 0), 0);
    return { name: b.name, sf: b.total_sf || 0, units: bUnits.length, revenue: rent };
  });

  // Unit breakdown
  const propUnits = units.filter(u => propBuildings.some(b => b.id === u.building_id));
  const unitData = propUnits.map(u => {
    const uLease = propLeases.find(l => l.unit_id === u.id);
    return { name: u.unit_id_code, tenant: uLease?.tenant_name || '(Vacant)', sf: u.square_feet || 0, rent: uLease ? (uLease.annual_rent || uLease.base_rent * 12 || 0) : 0, status: u.occupancy_status };
  });

  // Tenant breakdown
  const tenantMap = {};
  propLeases.forEach(l => {
    const key = l.tenant_name || 'Unknown';
    if (!tenantMap[key]) tenantMap[key] = { name: key, rent: 0, cam: 0, total: 0, leaseType: l.lease_type, leaseId: l.id, updatedDate: l.updated_date };
    tenantMap[key].rent += (l.annual_rent || l.base_rent * 12 || 0);
    const tc = propCams.filter(c => c.lease_id === l.id).reduce((s, c) => s + (c.annual_cam || 0), 0);
    tenantMap[key].cam += tc;
    tenantMap[key].total = tenantMap[key].rent + tenantMap[key].cam;
  });
  const tenantData = Object.values(tenantMap).sort((a, b) => b.total - a.total);

  if (selectedTenant) {
    return <TenantDrillDown tenant={selectedTenant} leases={propLeases} camCalcs={propCams} propertyName={property.name} onBack={() => setSelectedTenant(null)} />;
  }

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={onBack} className="text-slate-500 hover:text-slate-900">
          <ArrowLeft className="w-4 h-4 mr-1" /> Back
        </Button>
        <div className="h-5 w-px bg-slate-200" />
        <div>
          <h2 className="text-lg font-bold text-slate-900">{property.name}</h2>
          <p className="text-xs text-slate-500">{property.city}{property.state ? `, ${property.state}` : ''} • {property.property_type?.replace('_', ' ')}</p>
        </div>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: "Total Revenue", value: fmt(totalRevenue), color: "text-slate-900" },
          { label: "Base Rent", value: fmt(totalRent), color: "text-blue-700" },
          { label: "CAM Recovery", value: fmt(totalCam), color: "text-emerald-700" },
          { label: "Revenue / SF", value: property.total_sf > 0 ? `$${(totalRevenue / property.total_sf).toFixed(2)}` : '—', color: "text-purple-700" },
        ].map((k, i) => (
          <Card key={i}>
            <CardContent className="p-3">
              <p className="text-[10px] font-semibold text-slate-500 uppercase">{k.label}</p>
              <p className={`text-xl font-bold mt-0.5 ${k.color}`}>{k.value}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Monthly trend */}
      <MonthlyTrendChart leases={propLeases} camCalcs={propCams} />

      {/* Breakdowns */}
      <div className="grid lg:grid-cols-2 gap-5">
        <BreakdownSection
          icon={Building2}
          title="Revenue by Building"
          data={buildingData}
          columns={[
            { key: 'name', label: 'Building', bold: true },
            { key: 'units', label: 'Units' },
            { key: 'sf', label: 'SF', align: 'right', render: r => r.sf.toLocaleString() },
            { key: 'revenue', label: 'Revenue', align: 'right', bold: true, render: r => fmt(r.revenue) },
          ]}
        />
        <BreakdownSection
          icon={Layers}
          title="Revenue by Unit"
          data={unitData}
          columns={[
            { key: 'name', label: 'Unit', bold: true },
            { key: 'tenant', label: 'Tenant' },
            { key: 'sf', label: 'SF', align: 'right', render: r => r.sf.toLocaleString() },
            { key: 'rent', label: 'Revenue', align: 'right', bold: true, render: r => fmt(r.rent) },
            { key: 'status', label: 'Status', render: r => (
              <Badge variant="outline" className={`text-[9px] ${r.status === 'leased' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-50 text-slate-500'}`}>
                {r.status}
              </Badge>
            )},
          ]}
        />
      </div>

      {/* Tenant deep drill */}
      <BreakdownSection
        icon={Users}
        title="Revenue by Tenant"
        data={tenantData}
        columns={[
          { key: 'name', label: 'Tenant', bold: true },
          { key: 'rent', label: 'Rent', align: 'right', render: r => (
            <RevenueSourcePopover sourceType="lease" sourceId={r.leaseId} sourceName={r.name} amount={r.rent} lastUpdated={r.updatedDate}>
              {fmt(r.rent)}
            </RevenueSourcePopover>
          )},
          { key: 'cam', label: 'CAM', align: 'right', render: r => (
            <RevenueSourcePopover sourceType="cam" sourceName={r.name} amount={r.cam}>
              {fmt(r.cam)}
            </RevenueSourcePopover>
          )},
          { key: 'total', label: 'Total', align: 'right', bold: true, render: r => fmt(r.total) },
          { key: 'leaseType', label: 'Lease Type', render: r => (
            <Badge variant="outline" className="text-[9px] uppercase">{r.leaseType || '—'}</Badge>
          )},
        ]}
        onRowClick={(row) => setSelectedTenant(row)}
      />
    </div>
  );
}

/**
 * CsvImport v2 — per-user role assignment in review step
 * Upload → Review (with per-row role + edit) → Confirm & Send
 */
import React, { useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { Check, Loader2, ChevronRight, ChevronDown, Upload, Trash2, UserPlus, Settings, AlertTriangle } from "lucide-react";
import { supabase } from "@/services/supabaseClient";
import { toast } from "sonner";
import { ROLE_DEFINITIONS, parseRoles, getRoleDefaultModulePerms } from "@/lib/userPermissions";
import { AccessPanel } from "@/components/userManagement/AccessPanel";

const STEPS = ["Upload CSV", "Review & Assign", "Confirm"];

function parseCSV(text) {
  const lines = text.trim().split("\n").filter(Boolean);
  if (lines.length < 2) return [];

  // Normalize headers: lower case, remove spaces, remove quotes
  const rawHeaders = lines[0].split(",").map(h => h.trim().toLowerCase().replace(/^"|"$/g, ""));

  return lines.slice(1).map((line, idx) => {
    const vals = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map((v) => v.trim().replace(/^"|"$/g, ""));
    const row = {};
    rawHeaders.forEach((h, i) => { row[h] = vals[i] || ""; });

    // Header variants mapping
    const email = row.email || row.email_address || row["email address"] || "";
    const fullName = row.full_name || row["full name"] || row.name || row.customer_name || "";
    const phone = row.phone || row.phone_number || row["phone number"] || row.mobile || "";
    const roleString = row.role || row.roles || "viewer";

    return {
      _id: idx,
      full_name: fullName,
      email,
      phone,
      role: roleString,
      custom_role: "",
      module_permissions: null,
      page_permissions: null,
      _valid: /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email),
    };
  });
}

export default function CsvImport({ orgId, currentUser, onClose, onImported }) {
  const [step, setStep] = useState(0);
  const [rows, setRows] = useState([]);
  const [importing, setImporting] = useState(false);
  const [importProgress, setImportProgress] = useState({ current: 0, total: 0 });
  const [dragOver, setDragOver] = useState(false);
  const [accessOverrideId, setAccessOverrideId] = useState(null);
  const fileRef = useRef();

  const validRows = rows.filter((r) => r._valid);
  const invalidCount = rows.filter((r) => !r._valid).length;

  const handleFile = (file) => {
    if (!file || !file.name.endsWith(".csv")) { toast.error("Please upload a .csv file"); return; }
    const reader = new FileReader();
    reader.onload = (e) => { setRows(parseCSV(e.target.result)); setStep(1); };
    reader.readAsText(file);
  };

  const updateRow = (id, field, value) =>
    setRows((prev) => prev.map((r) => r._id === id ? { ...r, [field]: value } : r));

  const removeRow = (id) => setRows((prev) => prev.filter((r) => r._id !== id));

  const bulkSetRole = (role) => setRows((prev) => prev.map((r) => {
    let roles = parseRoles(r.role);
    if (!roles.includes(role)) roles = [...roles, role];
    return { ...r, role: roles.join(',') };
  }));

  const handleRoleToggle = (id, val, checked) => {
    setRows(prev => prev.map(r => {
      if (r._id !== id) return r;
      let roles = parseRoles(r.role);
      let next = checked === true 
        ? (roles.includes(val) ? roles : [...roles, val]) 
        : roles.filter(x => x !== val);
      return { ...r, role: next.join(',') };
    }));
  };
  const handleImport = async () => {
    setImportProgress({ current: 0, total: validRows.length });
    let successCount = 0;
    const failedEmails = [];
    for (const [idx, row] of validRows.entries()) {
      try {
        setImportProgress({ current: idx + 1, total: validRows.length });
        const { data, error } = await supabase.functions.invoke("invite-user", {
          body: {
            email: row.email,
            full_name: row.full_name || row.name || undefined,
            phone: row.phone || undefined,
            role: row.role || "viewer",
            custom_role: parseRoles(row.role || "viewer").includes("custom") ? row.custom_role : undefined,
            org_id: orgId,
            module_permissions: row.module_permissions || getRoleDefaultModulePerms(row.role || "viewer"),
            page_permissions: row.page_permissions || {},
          },
        });
        if (error) {
          console.error(`[CsvImport] Invite failed for ${row.email}:`, error);
          throw error;
        }
        if (data?.error) {
           console.error(`[CsvImport] Invite error from function for ${row.email}:`, data.error);
           throw new Error(data.error);
        }
        successCount++;
      } catch (err) { 
        console.error(`[CsvImport] Exception during invite for ${row.email}:`, err);
        failedEmails.push(row.email); 
      }
    }

    const logEntry = {
      org_id: orgId,
      uploaded_by: currentUser?.id,
      total_count: validRows.length,
      success_count: successCount,
      failed_count: failedEmails.length,
      failed_emails: failedEmails,
    };

    const { error: logErr } = await supabase.from("bulk_import_logs").insert(logEntry);
    if (logErr) console.error("[CsvImport] Failed to log import results:", logErr);

    setImporting(false);

    if (successCount > 0) {
      toast.success(`Imported ${successCount} user${successCount !== 1 ? "s" : ""}`);
      onImported();
      onClose();
    } else if (failedEmails.length > 0) {
      toast.error(`Fail to import any users. Checked logs.`);
    } else {
      toast.info("No valid users to import.");
    }
  };

  return (
    <div className="space-y-5">
      {/* Step bar */}
      <div className="flex items-center gap-2">
        {STEPS.map((s, i) => (
          <React.Fragment key={s}>
            <div className={`flex items-center gap-1.5 text-xs font-semibold ${i === step ? "text-blue-600" : i < step ? "text-emerald-600" : "text-slate-400"}`}>
              <div className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${i < step ? "bg-emerald-100 text-emerald-600" : i === step ? "bg-blue-100 text-blue-600" : "bg-slate-100 text-slate-400"}`}>
                {i < step ? <Check className="w-3 h-3" /> : i + 1}
              </div>
              {s}
            </div>
            {i < STEPS.length - 1 && <ChevronRight className="w-3 h-3 text-slate-300 shrink-0" />}
          </React.Fragment>
        ))}
      </div>

      {/* ── Step 0: Upload ── */}
      {step === 0 && (
        <div>
          <div
            onClick={() => fileRef.current?.click()}
            onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={(e) => { e.preventDefault(); setDragOver(false); handleFile(e.dataTransfer.files[0]); }}
            className={`border-2 border-dashed rounded-2xl p-12 text-center cursor-pointer transition-all ${dragOver ? "border-blue-400 bg-blue-50" : "border-slate-300 hover:border-blue-400 hover:bg-blue-50/30"}`}
          >
            <Upload className="w-10 h-10 text-slate-300 mx-auto mb-3" />
            <p className="text-sm font-semibold text-slate-700">Drop a CSV file here or click to browse</p>
            <p className="text-xs text-slate-400 mt-1">Columns: <code className="bg-slate-100 px-1 rounded">full_name, email, phone</code></p>
          </div>
          <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={(e) => handleFile(e.target.files[0])} />
        </div>
      )}

      {/* ── Step 1: Review & Assign Role per User ── */}
      {step === 1 && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="text-[11px] text-slate-500 font-medium bg-slate-100 px-2 py-0.5 rounded-full">
                <span className="text-emerald-600 font-bold">{validRows.length}</span> Valid
              </span>
              {invalidCount > 0 && (
                <span className="text-[11px] text-amber-600 font-medium bg-amber-50 px-2 py-0.5 rounded-full flex items-center gap-1">
                  <AlertTriangle className="w-3 h-3" /> {invalidCount} Invalid/Skipped
                </span>
              )}
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[10px] text-slate-400 uppercase font-bold tracking-tight mr-1">Quick assign role:</span>
              {["viewer", "editor", "manager", "finance"].map((r) => (
                <button key={r} onClick={() => bulkSetRole(r)} className="text-[10px] px-2 py-1 rounded bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold capitalize flex items-center gap-1.5 transition-colors">
                  <span className={`w-1.5 h-1.5 rounded-full ${ROLE_DEFINITIONS.find(d => d.value === r)?.color.replace("text-", "bg-").split(" ")[0]}`}></span>
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="border border-slate-200 rounded-xl overflow-hidden bg-white shadow-sm">
            {/* Table Header */}
            <div className="grid grid-cols-[1.28fr_1.5fr_1fr_1.4fr_auto] gap-2 px-3 py-2 bg-slate-50 border-b border-slate-200 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              <span>Member Info</span>
              <span>Email Address</span>
              <span>Phone</span>
              <span>Roles & Access</span>
              <span className="w-16"></span>
            </div>

            {/* Table Body */}
            <div className="max-h-80 overflow-y-auto divide-y divide-slate-100">
              {rows.map((row) => (
                <div key={row._id} className={`grid grid-cols-[1.28fr_1.5fr_1fr_1.4fr_auto] gap-2 items-center px-3 py-2.5 transition-colors ${!row._valid ? 'bg-amber-50/20 opacity-70' : 'hover:bg-slate-50/50'}`}>
                  {/* Name */}
                  <div className="flex items-center gap-2 min-w-0">
                    {!row._valid && <AlertTriangle className="w-3.5 h-3.5 text-amber-500 shrink-0" />}
                    <Input
                      value={row.full_name}
                      onChange={(e) => updateRow(row._id, "full_name", e.target.value)}
                      placeholder="Enter name..."
                      className="h-8 text-xs border-0 bg-transparent px-0 focus-visible:ring-0 font-medium text-slate-700 hover:bg-slate-100/50 rounded-md transition-colors"
                    />
                  </div>

                  {/* Email */}
                  <span className="text-xs text-slate-500 truncate font-medium" title={row.email}>{row.email}</span>

                  {/* Phone */}
                  <Input
                    value={row.phone}
                    onChange={(e) => updateRow(row._id, "phone", e.target.value)}
                    placeholder="—"
                    className="h-8 text-xs border-0 bg-transparent px-0 focus-visible:ring-0 text-slate-500 hover:bg-slate-100/50 rounded-md transition-colors"
                  />

                  {/* Roles Selector */}
                  <div className="space-y-1">
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button variant="outline" className={`h-8 text-xs w-full justify-between items-center text-left font-medium px-2.5 ${!row.role ? 'text-slate-400 border-dashed border-slate-300' : 'text-slate-700 border-slate-200'}`}>
                          <span className="truncate flex-1">
                             {!row.role ? "Select Roles" : parseRoles(row.role).map(r => ROLE_DEFINITIONS.find(d => d.value === r)?.label || r).join(', ')}
                          </span>
                          <ChevronDown className="w-3 h-3 opacity-30 shrink-0 ml-1.5" />
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-56 p-2 shadow-xl border-slate-200" align="start">
                        <div className="space-y-1">
                          <p className="text-[10px] font-bold text-slate-400 uppercase px-2 py-1 tracking-tight">Assign Permissions</p>
                          {ROLE_DEFINITIONS.filter((r) => r.value !== "org_admin").map((r) => (
                            <div key={r.value} className="flex flex-row items-center space-x-2.5 px-2 py-1.5 hover:bg-blue-50/50 rounded-md transition-colors cursor-pointer group" 
