}

// ── Access Tab ────────────────────────────────────────────────────────────────
export function AccessTab({ role, modulePerms, setModulePerms, pagePerms, setPagePerms, enabledModules }) {
  const [search, setSearch] = useState("");
  const [expanded, setExpanded] = useState({});
  const roleDefault = useMemo(() => getRoleDefaultModulePerms(role), [role]);
  const diffs = useMemo(() => getPermDiff(roleDefault, modulePerms), [roleDefault, modulePerms]);

  const setModuleLevel = (key, level) => {
    setModulePerms((p) => ({ ...p, [key]: level }));
    const mod = MODULE_DEFINITIONS[key];
    if (mod?.pages) {
      setPagePerms((p) => {
        const next = { ...p };
        mod.pages.forEach((pg) => { next[pg] = level; });
        return next;
      });
    }
  };

  const bulkApply = (level) => {
    const next = {};
    Object.keys(modulePerms).forEach((k) => { next[k] = level; });
    setModulePerms(next);
    const pageNext = {};
    Object.values(MODULE_DEFINITIONS).forEach((mod) => {
      mod?.pages?.forEach((pg) => { pageNext[pg] = level; });
    });
    setPagePerms(pageNext);
  };

  return (
    <div>
      {/* Toolbar */}
      <div className="flex items-center gap-2 mb-3">
        <div className="relative flex-1">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search modules..."
            className="pl-8 h-8 text-sm"
          />
        </div>
        <Button size="sm" variant="outline" className="h-8 text-xs" onClick={() => bulkApply("full")}>All Full</Button>
        <Button size="sm" variant="outline" className="h-8 text-xs" onClick={() => bulkApply("read_only")}>All Read</Button>
        <Button size="sm" variant="outline" className="h-8 text-xs" onClick={() => bulkApply("none")}>All None</Button>
      </div>

      {diffs.length > 0 && (
        <div className="mb-3 px-3 py-2 bg-amber-50 border border-amber-200 rounded-lg text-xs text-amber-700">
          <strong>{diffs.length} override{diffs.length !== 1 ? "s" : ""}</strong> from role defaults:{" "}
          {diffs.slice(0, 3).map((d) => d.label).join(", ")}{diffs.length > 3 ? ` +${diffs.length - 3} more` : ""}
        </div>
      )}

      <div className="space-y-2 max-h-[42vh] overflow-y-auto pr-1">
        {Object.entries(MODULE_DOMAINS).map(([domain, keys]) => {
          const visibleKeys = keys.filter((k) => {
            const mod = MODULE_DEFINITIONS[k];
            if (!mod) return false;
            if (search && !mod.label.toLowerCase().includes(search.toLowerCase())) return false;
            return true;
          });
          if (visibleKeys.length === 0) return null;

          return (
            <div key={domain}>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-1 mb-1.5">{domain}</p>
              {visibleKeys.map((key) => {
                const mod = MODULE_DEFINITIONS[key];
                if (!mod) return null;
                const modLevel = modulePerms[key] || "none";
                const defLevel = roleDefault[key] || "none";
                const isOverridden = modLevel !== defLevel;
                const isExp = expanded[key];

                return (
                  <div key={key} className="border border-slate-200 rounded-xl overflow-hidden mb-2">
                    <div className={`flex items-center justify-between px-3 py-2.5 ${isOverridden ? "bg-amber-50" : "bg-slate-50"}`}>
                      <div className="flex items-center gap-2 min-w-0">
                        <button type="button" onClick={() => setExpanded((e) => ({ ...e, [key]: !e[key] }))} className="text-slate-400 hover:text-slate-600 shrink-0">
                          {isExp ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />}
                        </button>
                        <span className="text-xs font-semibold text-slate-800 truncate">{mod.label}</span>
                        {isOverridden && <span className="text-[9px] bg-amber-200 text-amber-700 rounded px-1 font-bold shrink-0">Override</span>}
                      </div>
                      <AccessChip value={modLevel} onChange={(v) => setModuleLevel(key, v)} compact />
                    </div>
                    {isExp && mod.pages && (
                      <div className="divide-y divide-slate-50 border-t border-slate-100">
                        {mod.pages.map((pg) => {
                          const pgLevel = pagePerms[pg] || modLevel;
                          return (
                            <div key={pg} className="flex items-center justify-between px-5 py-2 bg-white">
                              <span className="text-xs text-slate-500">{pg.replace(/([A-Z])/g, " $1").trim()}</span>
                              <AccessChip value={pgLevel} onChange={(v) => setPagePerms((p) => ({ ...p, [pg]: v }))} compact />
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Capabilities Tab ──────────────────────────────────────────────────────────
export function CapabilitiesTab({ role, capabilities, setCapabilities }) {
  const roleObj = ROLE_DEFINITIONS.find((r) => r.value === role);
  const defaults = roleObj?.defaultCapabilities || {};

  return (
    <div>
      <p className="text-xs text-slate-500 mb-4">
        Capabilities are workflow-level permissions that go beyond page access. They control specific actions within the platform.
      </p>
      <div className="space-y-3">
        {CAPABILITY_DEFINITIONS.map(({ key, label, description }) => {
          const isDefault = !!defaults[key];
          const isActive = capabilities[key] !== undefined ? capabilities[key] : isDefault;
          const isOverridden = capabilities[key] !== undefined && capabilities[key] !== isDefault;
          return (
            <div key={key} className={`flex items-center justify-between p-3 rounded-xl border transition-colors ${isActive ? "bg-emerald-50 border-emerald-200" : "bg-white border-slate-200"}`}>
              <div>
                <div className="flex items-center gap-2">
                  <Zap className={`w-3.5 h-3.5 ${isActive ? "text-emerald-600" : "text-slate-300"}`} />
                  <span className="text-sm font-semibold text-slate-800">{label}</span>
                  {isOverridden && <span className="text-[9px] bg-amber-200 text-amber-700 rounded px-1 font-bold">Override</span>}
                  {isDefault && !isOverridden && <span className="text-[9px] bg-slate-100 text-slate-500 rounded px-1">Role default</span>}
                </div>
                <p className="text-xs text-slate-500 mt-0.5 ml-5">{description}</p>
              </div>
              <Switch
                checked={isActive}
                onCheckedChange={(v) => setCapabilities((c) => ({ ...c, [key]: v }))}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ── Summary Panel ─────────────────────────────────────────────────────────────
export function SummaryPanel({ role, modulePerms, pagePerms, capabilities, fullName }) {
  const roleObj = ROLE_DEFINITIONS.find((r) => r.value === role);
  const diffs = useMemo(() => {
    const defaults = getRoleDefaultModulePerms(role);
    return getPermDiff(defaults, modulePerms);
  }, [role, modulePerms]);

  const activeCaps = CAPABILITY_DEFINITIONS.filter(({ key }) => {
    const defVal = roleObj?.defaultCapabilities?.[key] || false;
    return capabilities[key] !== undefined ? capabilities[key] : defVal;
  });

  const modulesByLevel = useMemo(() => {
    const groups = { full: [], read_only: [], none: [] };
    Object.entries(modulePerms).forEach(([key, val]) => {
      const mod = MODULE_DEFINITIONS[key];
      if (mod) groups[val]?.push(mod.label);
    });
    return groups;
  }, [modulePerms]);

  return (
    <div className="w-60 shrink-0 border-l border-slate-100 pl-4 overflow-y-auto">
      <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-3">Permission Summary</p>

      {/* Who */}
      <div className="mb-4">
        <p className="text-xs text-slate-500 mb-1">Editing</p>
        <p className="text-sm font-bold text-slate-900 truncate">{fullName || "New User"}</p>
        {roleObj && <Badge className={`text-[10px] mt-1 ${roleObj.color}`}>{roleObj.label}</Badge>}
      </div>

      {/* Overrides */}
      {diffs.length > 0 && (
        <div className="mb-4">
          <p className="text-xs text-slate-500 mb-2">Overrides ({diffs.length})</p>
          <div className="space-y-1">
            {diffs.slice(0, 5).map((d) => (
              <div key={d.key} className="flex items-center gap-1.5 text-[11px]">
                <span className="text-slate-400">{d.label}:</span>
                <span className="text-slate-400 line-through">{d.from}</span>
                <span className="text-blue-600 font-medium">→ {d.to}</span>
              </div>
            ))}
            {diffs.length > 5 && <p className="text-[10px] text-slate-400">+{diffs.length - 5} more</p>}
          </div>
        </div>
      )}

      {/* Module summary */}
      <div className="mb-4 space-y-2">
        {modulesByLevel.full.length > 0 && (
          <div>
            <p className="text-[10px] font-semibold text-emerald-600 mb-1">Full Access</p>
            <p className="text-[11px] text-slate-500 leading-relaxed">{modulesByLevel.full.join(", ")}</p>
          </div>
        )}
        {modulesByLevel.read_only.length > 0 && (
          <div>
            <p className="text-[10px] font-semibold text-blue-600 mb-1">Read Only</p>
            <p className="text-[11px] text-slate-500 leading-relaxed">{modulesByLevel.read_only.join(", ")}</p>
          </div>
        )}
        {modulesByLevel.none.length > 0 && (
          <div>
            <p className="text-[10px] font-semibold text-slate-400 mb-1">No Access</p>
            <p className="text-[11px] text-slate-400 leading-relaxed">{modulesByLevel.none.join(", ")}</p>
          </div>
        )}
      </div>

      {/* Capabilities */}
      {activeCaps.length > 0 && (
        <div>
          <p className="text-xs text-slate-500 mb-2">Capabilities</p>
          <div className="space-y-1">
            {activeCaps.map((c) => (
              <div key={c.key} className="flex items-center gap-1.5 text-[11px] text-emerald-700">
                <Zap className="w-3 h-3 shrink-0" />
                {c.label}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState } from "react";
import { expenseService } from "@/services/expenseService";
import { uploadFile, extractDataFromUploadedFile } from "@/services/integrations";
import { useQueryClient } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ArrowLeft, Upload, Download, CheckCircle2, Loader2 } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { createPageUrl } from "@/utils";

const systemFields = ["expense_date", "category", "amount", "vendor", "recoverable_flag", "description"];

export default function BulkImport() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [fileUrl, setFileUrl] = useState("");
  const [uploading, setUploading] = useState(false);
  const [extractedRows, setExtractedRows] = useState([]);
  const [columnMap, setColumnMap] = useState({});
  const [validatedRows, setValidatedRows] = useState([]);

  const handleFileUpload = async (e) => {
    const f = e.target.files[0];
    if (!f) return;
    setFile(f);
    setUploading(true);
    const { file_url } = await uploadFile({ file: f });
    setFileUrl(file_url);

    const result = await extractDataFromUploadedFile({
      file_url,
      json_schema: {
        type: "object",
        properties: {
          columns: { type: "array", items: { type: "string" } },
          rows: { type: "array", items: { type: "object" } }
        }
      }
    });

    if (result.output) {
      const cols = result.output.columns || Object.keys(result.output.rows?.[0] || {});
      const autoMap = {};
      cols.forEach(c => {
        const lower = c.toLowerCase();
        if (lower.includes('date')) autoMap[c] = 'expense_date';
        else if (lower.includes('category') || lower.includes('type')) autoMap[c] = 'category';
        else if (lower.includes('amount') || lower.includes('cost')) autoMap[c] = 'amount';
        else if (lower.includes('vendor') || lower.includes('supplier')) autoMap[c] = 'vendor';
        else if (lower.includes('recover') || lower.includes('class')) autoMap[c] = 'recoverable_flag';
        else if (lower.includes('desc') || lower.includes('note')) autoMap[c] = 'description';
      });
      setColumnMap(autoMap);
      setExtractedRows(result.output.rows || (Array.isArray(result.output) ? result.output : []));
    }
    setUploading(false);
    setStep(2);
  };

  const runValidation = () => {
    const validated = extractedRows.map((row, i) => {
      const warnings = [];
      const errors = [];
      const mappedRow = {};
      Object.entries(columnMap).forEach(([col, field]) => { mappedRow[field] = row[col]; });

      if (!mappedRow.amount || isNaN(parseFloat(String(mappedRow.amount).replace(/[$,]/g, '')))) errors.push("Amount field is empty — required field");
      if (!mappedRow.category) errors.push("Category is empty");
      if (mappedRow.expense_date && !/^\d{4}-\d{2}-\d{2}$/.test(mappedRow.expense_date)) warnings.push("Date format mismatch — expected YYYY-MM-DD");
      if (mappedRow.recoverable_flag?.toLowerCase() === 'conditional') warnings.push("Conditional recoverable — will require lease validation check on import");

      return { ...mappedRow, row_num: i + 1, warnings, errors, status: errors.length > 0 ? 'error' : warnings.length > 0 ? 'warning' : 'ready', original: row };
    });
    setValidatedRows(validated);
    setStep(3);
  };

  const importData = async () => {
    const ready = validatedRows.filter(r => r.status !== 'error');
    for (const row of ready) {
      await expenseService.create({
        date: row.expense_date,
        category: row.category?.toLowerCase().replace(/\s+/g, '_') || "other",
        amount: parseFloat(String(row.amount).replace(/[$,]/g, '')) || 0,
        vendor: row.vendor || "",
        description: row.description || "",
        classification: row.recoverable_flag?.toLowerCase().includes('non') ? 'non_recoverable' : row.recoverable_flag?.toLowerCase().includes('cond') ? 'conditional' : 'recoverable',
        source: "import",
        org_id: "default",
        fiscal_year: new Date().getFullYear()
      });
    }
    queryClient.invalidateQueries({ queryKey: ['expenses'] });
    setStep(4);
  };

  const readyCount = validatedRows.filter(r => r.status === 'ready').length;
  const warningCount = validatedRows.filter(r => r.status === 'warning').length;
  const errorCount = validatedRows.filter(r => r.status === 'error').length;

  const downloadTemplate = () => {
    const csv = "Date,Category,Amount,Vendor,Recoverable,Description\n2025-04-01,HVAC Maintenance,$12400,Arizona Air Systems,Recoverable,Monthly service";
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href = url; a.download = "expense_template.csv"; a.click();
    URL.revokeObjectURL(url);
  };

  const stepLabels = ["Upload File", "Map Columns", "Validate", "Complete"];

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <Link to={createPageUrl("Expenses")} className="text-sm text-slate-500 hover:text-slate-700 flex items-center gap-1"><ArrowLeft className="w-4 h-4" /> Back to Expenses</Link>

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Bulk Expense Import</h1>
          <p className="text-sm text-slate-500">Import CSV or Excel</p>
        </div>
        <Button variant="outline" onClick={downloadTemplate}><Download className="w-4 h-4 mr-2" />Download Template</Button>
      </div>

      {/* Steps */}
      <div className="flex items-center gap-2">
        {stepLabels.map((s, i) => (
          <React.Fragment key={i}>
            <div className="flex items-center gap-2">
              <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold ${step > i + 1 ? 'bg-emerald-500 text-white' : step === i + 1 ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                {step > i + 1 ? <CheckCircle2 className="w-3.5 h-3.5" /> : i + 1}
              </div>
              <span className={`text-sm ${step >= i + 1 ? 'text-slate-900 font-medium' : 'text-slate-400'}`}>{s}</span>
            </div>
            {i < 3 && <div className={`flex-1 h-0.5 ${step > i + 1 ? 'bg-emerald-500' : 'bg-slate-200'}`} />}
          </React.Fragment>
        ))}
      </div>

      {/* Step 1: Upload */}
      {step === 1 && (
        <Card>
          <CardContent className="p-12 text-center">
            <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4"><Upload className="w-8 h-8 text-slate-400" /></div>
            <h2 className="text-lg font-bold text-slate-900 mb-2">Upload Expense File</h2>
            <p className="text-sm text-slate-500 mb-6">Drag and drop your CSV or Excel file, or click to browse.</p>
            <label>
              <input type="file" accept=".csv,.xlsx,.xls" className="hidden" onChange={handleFileUpload} />
              <Button asChild className="bg-[#1a2744] hover:bg-[#243b67] cursor-pointer"><span>{uploading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}Browse Files</span></Button>
            </label>
            <p className="text-xs text-slate-400 mt-3">Supported: CSV, XLSX</p>
          </CardContent>
        </Card>
      )}

      {/* Step 2: Map Columns */}
      {step === 2 && (
        <Card>
          <CardContent className="p-6 space-y-4">
            <div>
              <h2 className="text-lg font-bold text-slate-900">Column Mapping</h2>
              <p className="text-sm text-slate-500">Map columns from your file to the system fields. Auto-detected matches are pre-filled.</p>
            </div>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="text-[11px]">YOUR FILE COLUMN</TableHead>
                  <TableHead className="text-[11px]">MAPS TO</TableHead>
                  <TableHead className="text-[11px]">SAMPLE VALUE</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {Object.keys(extractedRows[0] || {}).map(col => (
                  <TableRow key={col}>
                    <TableCell className="text-sm text-blue-600 font-medium">{col}</TableCell>
                    <TableCell>
                      <Select value={columnMap[col] || ""} onValueChange={v => setColumnMap({...columnMap, [col]: v})}>
                        <SelectTrigger className="w-44 h-8 text-xs"><SelectValue placeholder="Select..." /></SelectTrigger>
                        <SelectContent>
                          {systemFields.map(f => <SelectItem key={f} value={f}>{f}</SelectItem>)}
                        </SelectContent>
                      </Select>
                    </TableCell>
                    <TableCell className="text-sm text-slate-400">{String(extractedRows[0]?.[col] || "")}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
            <div className="flex justify-between">
              <Button variant="outline" onClick={() => setStep(1)}>Back</Button>
              <Button className="bg-blue-600 hover:bg-blue-700" onClick={runValidation}>Run Validation</Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Step 3: Validate */}
      {step === 3 && (
        <div className="space-y-4">
          <div className="grid grid-cols-4 gap-4">
            <Card className="bg-slate-50"><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">Total Rows</p><p className="text-2xl font-bold">{validatedRows.length}</p></CardContent></Card>
            <Card className="bg-emerald-50"><CardContent className="p-4"><p className="text-[10px] font-semibold text-emerald-600 uppercase">Ready to Import</p><p className="text-2xl font-bold text-emerald-700">{readyCount}</p></CardContent></Card>
            <Card className="bg-amber-50"><CardContent className="p-4"><p className="text-[10px] font-semibold text-amber-600 uppercase">Warnings (importable)</p><p className="text-2xl font-bold text-amber-700">{warningCount}</p></CardContent></Card>
            <Card className="bg-red-50"><CardContent className="p-4"><p className="text-[10px] font-semibold text-red-600 uppercase">Errors (blocked)</p><p className="text-2xl font-bold text-red-700">{errorCount}</p></CardContent></Card>
          </div>

          <Card>
            <Table>
              <TableHeader>
                <TableRow className="bg-slate-50">
                  <TableHead className="text-[11px]">ROW</TableHead>
                  <TableHead className="text-[11px]">DATE</TableHead>
                  <TableHead className="text-[11px]">CATEGORY</TableHead>
                  <TableHead className="text-[11px]">AMOUNT</TableHead>
                  <TableHead className="text-[11px]">VENDOR</TableHead>
                  <TableHead className="text-[11px]">RECOVERABLE</TableHead>
                  <TableHead className="text-[11px]">STATUS</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {validatedRows.map(r => (
                  <React.Fragment key={r.row_num}>
                    <TableRow className={r.status === 'error' ? 'bg-red-50/50' : r.status === 'warning' ? 'bg-amber-50/50' : ''}>
                      <TableCell className="text-sm">{r.row_num}</TableCell>
                      <TableCell className="text-sm">{r.expense_date || '—'}</TableCell>
                      <TableCell className="text-sm font-medium">{r.category}</TableCell>
                      <TableCell className="text-sm font-mono">{r.amount}</TableCell>
                      <TableCell className="text-sm">{r.vendor}</TableCell>
                      <TableCell><Badge className={r.recoverable_flag?.toLowerCase().includes('non') ? 'bg-red-100 text-red-700 text-[10px]' : r.recoverable_flag?.toLowerCase().includes('cond') ? 'bg-amber-100 text-amber-700 text-[10px]' : 'bg-emerald-100 text-emerald-700 text-[10px]'}>{r.recoverable_flag || 'Recoverable'}</Badge></TableCell>
                      <TableCell><Badge className={r.status === 'error' ? 'bg-red-100 text-red-600' : r.status === 'warning' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-700'} >{r.status === 'ready' ? '✓ Ready' : r.status === 'warning' ? '⚠ Warning' : '✕ Error'}</Badge></TableCell>
                    </TableRow>
                    {(r.warnings.length > 0 || r.errors.length > 0) && (
                      <TableRow>
                        <TableCell colSpan={7} className="py-1 px-8">
                          {r.warnings.map((w, i) => <p key={i} className="text-xs text-amber-600">⚠ {w}</p>)}
                          {r.errors.map((w, i) => <p key={i} className="text-xs text-red-600">✕ {w}</p>)}
                        </TableCell>
                      </TableRow>
                    )}
                  </React.Fragment>
                ))}
              </TableBody>
            </Table>
          </Card>

          <div className="flex justify-between">
            <Button variant="outline" onClick={() => setStep(2)}>Back</Button>
            <Button className="bg-emerald-600 hover:bg-emerald-700" onClick={importData} disabled={readyCount + warningCount === 0}>
              Import {readyCount + warningCount} Rows
            </Button>
          </div>
        </div>
      )}

      {/* Step 4: Complete */}
      {step === 4 && (
        <Card>
          <CardContent className="p-12 text-center">
            <CheckCircle2 className="w-16 h-16 text-emerald-500 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-slate-900 mb-2">Import Complete!</h2>
            <p className="text-sm text-slate-500 mb-6">{readyCount + warningCount} expenses imported successfully.</p>
            <Link to={createPageUrl("Expenses")}><Button className="bg-blue-600 hover:bg-blue-700">View Expenses</Button></Link>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

