              <TableHead className="text-[10px]">TYPE</TableHead>
              <TableHead className="text-[10px]">CATEGORY / MAPPING</TableHead>
              <TableHead className="text-[10px]">STATUS</TableHead>
              <TableHead className="text-[10px] w-20">ACTIONS</TableHead>
