const confidenceColor = (score) => {
  if (score >= 90) return "bg-emerald-100 text-emerald-700";
  if (score >= 75) return "bg-amber-100 text-amber-700";
  return "bg-red-100 text-red-700";
};

export default function LeaseReview() {
  const urlParams = new URLSearchParams(window.location.search);
  const leaseId = urlParams.get("id");
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const [showSignature, setShowSignature] = useState(false);
  const [showApproval, setShowApproval] = useState(false);
  const [allocationModel, setAllocationModel] = useState("pro_rata");
  const [vacancyHandling, setVacancyHandling] = useState("exclude");
  const [editingField, setEditingField] = useState(null);
  const [editValue, setEditValue] = useState("");

  const { data: lease, isLoading } = useQuery({
    queryKey: ['lease', leaseId],
    queryFn: () => leaseService.filter({ id: leaseId }),
    enabled: !!leaseId,
    select: data => data?.[0],
  });

  const { data: stakeholders = [] } = useOrgQuery("Stakeholder");

  const updateLeaseMutation = useMutation({
    mutationFn: ({ id, data }) => leaseService.update(id, data),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['lease', leaseId] }),
  });

  // No lease ID or lease not found
  if (!leaseId) {
    return (
      <div className="p-6 flex flex-col items-center justify-center h-96">
        <FileX className="w-12 h-12 text-slate-300 mb-4" />
        <h2 className="text-xl font-bold text-slate-900 mb-2">No Lease Selected</h2>
        <p className="text-sm text-slate-500 mb-4">Please select a lease from the Leases page to review.</p>
        <Link to={createPageUrl("Leases")}><Button>Go to Leases</Button></Link>
      </div>
    );
  }

  if (isLoading) {
    return <div className="flex items-center justify-center h-96"><Loader2 className="w-6 h-6 animate-spin text-slate-400" /></div>;
  }

  if (!lease) {
    return (
      <div className="p-6 flex flex-col items-center justify-center h-96">
        <FileX className="w-12 h-12 text-slate-300 mb-4" />
        <h2 className="text-xl font-bold text-slate-900 mb-2">Lease Not Found</h2>
        <p className="text-sm text-slate-500 mb-4">This lease may have been deleted or you don't have access.</p>
        <Link to={createPageUrl("Leases")}><Button>Go to Leases</Button></Link>
      </div>
    );
  }

  // Build fields from actual lease data — use extraction confidence if available
  const scores = lease.extraction_data?.confidence_scores || {};
  const getConf = (key, fallback = 85) => (typeof scores[key] === 'number' ? scores[key] : fallback);

  const fields = {
    "Basic Terms": [
      { key: "tenant_name", label: "TENANT NAME", value: lease.tenant_name || "—", confidence: getConf("tenant_name", 98) },
      { key: "lease_type", label: "LEASE TYPE", value: lease.lease_type || "—", confidence: getConf("lease_type", 95) },
      { key: "start_date", label: "START DATE", value: lease.start_date || "—", confidence: getConf("start_date", 94) },
      { key: "end_date", label: "END DATE", value: lease.end_date || "—", confidence: getConf("end_date", 92) },
    ],
    "Financial Terms": [
      { key: "rent_per_sf", label: "BASE RENT ($/SF/YR)", value: lease.rent_per_sf ? `$${lease.rent_per_sf}` : "—", confidence: getConf("rent_per_sf", 92) },
      { key: "total_sf", label: "TOTAL SF", value: lease.total_sf?.toLocaleString() || "—", confidence: getConf("total_sf", 99) },
      { key: "annual_rent", label: "ANNUAL RENT", value: lease.annual_rent ? `$${lease.annual_rent.toLocaleString()}` : "—", confidence: getConf("annual_rent", 99) },
      { key: "escalation_rate", label: "RENT ESCALATION", value: lease.escalation_rate ? `${lease.escalation_rate}% ${lease.escalation_type || ''}` : "—", confidence: getConf("escalation_rate", 78) },
    ],
    "Escalation & Renewal": [
      { key: "escalation_timing", label: "ESCALATION TIMING", value: lease.escalation_timing === 'calendar_year' ? 'Calendar Year (Jan 1)' : 'Lease Anniversary', confidence: getConf("escalation_timing", 90) },
      { key: "free_rent_months", label: "FREE RENT PERIODS", value: lease.free_rent_months || "—", confidence: getConf("free_rent_months", 91) },
      { key: "ti_allowance", label: "TI ALLOWANCE", value: lease.ti_allowance ? `$${lease.ti_allowance.toLocaleString()}` : "—", confidence: getConf("ti_allowance", 88) },
      { key: "renewal_type", label: "RENEWAL TYPE", value: lease.renewal_type || "—", confidence: getConf("renewal_type", 78) },
      { key: "renewal_options", label: "RENEWAL OPTIONS", value: lease.renewal_options || "—", confidence: getConf("renewal_options", 64) },
      { key: "renewal_notice_months", label: "RENEWAL NOTICE (MONTHS)", value: lease.renewal_notice_months || "—", confidence: getConf("renewal_notice_months", 72) },
    ],
    "CAM & Management": [
      { key: "cam_cap_type", label: "CAM CAP TYPE", value: lease.cam_cap_type || "None", confidence: getConf("cam_cap_type", 95) },
      { key: "cpi_index", label: "CPI INDEX SOURCE", value: lease.cpi_index || "N/A", confidence: getConf("cpi_index", 90) },
      { key: "admin_fee_pct", label: "ADMIN FEE %", value: lease.admin_fee_pct ? `${lease.admin_fee_pct}%` : "N/A", confidence: getConf("admin_fee_pct", 97) },
      { key: "management_fee_basis", label: "MGMT FEE BASIS", value: lease.management_fee_basis === 'tenant_annual_rent' ? '% of Tenant Annual Rent' : 'CAM Pool Pro-Rata', confidence: getConf("management_fee_basis", 88) },
      { key: "gross_up_clause", label: "GROSS-UP PROVISION", value: lease.gross_up_clause ? 'Yes' : 'No', confidence: getConf("gross_up_clause", 94) },
      { key: "hvac_responsibility", label: "HVAC RESPONSIBILITY", value: (lease.hvac_responsibility || 'landlord').replace('_', ' '), confidence: getConf("hvac_responsibility", 92) },
      { key: "hvac_landlord_limit", label: "HVAC LANDLORD LIMIT", value: lease.hvac_landlord_limit ? `$${lease.hvac_landlord_limit.toLocaleString()}` : "No limit", confidence: getConf("hvac_landlord_limit", 85) },
    ],
    "Revenue & Recon": [
      { key: "percentage_rent", label: "PERCENTAGE RENT", value: lease.percentage_rent ? `${lease.percentage_rent_rate}% over $${(lease.percentage_rent_breakpoint || 0).toLocaleString()}` : "No", confidence: getConf("percentage_rent", 90) },
      { key: "sales_reporting_frequency", label: "SALES REPORTING FREQ.", value: (lease.sales_reporting_frequency || 'annual'), confidence: getConf("sales_reporting_frequency", 88) },
      { key: "recon_deadline_days", label: "RECON DEADLINE", value: `${lease.recon_deadline_days || 90} days after year-end`, confidence: getConf("recon_deadline_days", 92) },
      { key: "recon_collection_limit_months", label: "COLLECTION LIMIT", value: `${lease.recon_collection_limit_months || 12} months`, confidence: getConf("recon_collection_limit_months", 90) },
      { key: "version", label: "LEASE VERSION", value: `v${lease.version || 1}`, confidence: 99 },
    ],
  };

  const allFieldsFlat = Object.values(fields).flat();
  const highConf = allFieldsFlat.filter(f => f.confidence >= 90).length;
  const medConf = allFieldsFlat.filter(f => f.confidence >= 75 && f.confidence < 90).length;
  const lowConf = allFieldsFlat.filter(f => f.confidence < 75).length;

  // Dynamic validation checks based on actual lease data
  const validationChecks = [];
  if (lease.start_date && lease.end_date) {
    const startOk = new Date(lease.start_date) < new Date(lease.end_date);
    validationChecks.push({ pass: startOk, label: "Start date < End date", detail: startOk ? `${lease.start_date} < ${lease.end_date}` : "End date is before start date" });
  }
  if (lease.tenant_name) {
    validationChecks.push({ pass: true, label: "Tenant name present", detail: `${lease.tenant_name} verified` });
  }
  if (lease.annual_rent) {
    validationChecks.push({ pass: lease.annual_rent > 0, label: "Annual rent > $0", detail: `$${lease.annual_rent.toLocaleString()}` });
  }
  if (lease.total_sf) {
    validationChecks.push({ pass: lease.total_sf > 0, label: "Square footage present", detail: `${lease.total_sf.toLocaleString()} SF` });
  }
  const hasLowConf = lowConf > 0;
  if (hasLowConf) {
    validationChecks.push({ pass: false, label: "All confidence scores ≥ 70%", detail: `${lowConf} field(s) below threshold — human review required` });
  } else {
    validationChecks.push({ pass: true, label: "All confidence scores ≥ 70%", detail: "No low-confidence fields detected" });
  }

  const passCount = validationChecks.filter(v => v.pass).length;

  const handleApprove = async () => {
    await updateLeaseMutation.mutateAsync({ id: lease.id, data: { status: "budget_ready" } });
    setShowApproval(false);
  };

  const handleFieldEdit = (field) => {
    setEditingField(field);
    // Get raw value from lease
    const raw = lease[field.key];
    setEditValue(raw !== undefined && raw !== null ? String(raw) : "");
  };

  const handleFieldSave = async () => {
    if (!editingField) return;
    let val = editValue;
    // Try to parse numbers
    if (["rent_per_sf", "total_sf", "annual_rent", "escalation_rate", "admin_fee_pct", "ti_allowance", "hvac_landlord_limit", "renewal_notice_months", "recon_deadline_days", "recon_collection_limit_months", "percentage_rent_rate", "percentage_rent_breakpoint", "management_fee_pct", "base_rent", "cam_cap_rate"].includes(editingField.key)) {
      val = parseFloat(val) || 0;
    }
    if (["gross_up_clause", "percentage_rent", "admin_fee_allowed"].includes(editingField.key)) {
      val = val === "true" || val === "Yes" || val === "yes";
    }
    await updateLeaseMutation.mutateAsync({ id: lease.id, data: { [editingField.key]: val } });
    setEditingField(null);
  };

  return (
    <div className="p-6 space-y-6">
      <Link to={createPageUrl("Leases")} className="text-sm text-slate-500 hover:text-slate-700 flex items-center gap-1">
        <ArrowLeft className="w-4 h-4" /> Back to Leases
      </Link>

      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Lease Review & Validation</h1>
          <p className="text-sm text-slate-500">{lease.tenant_name} — {lease.total_sf ? `${lease.total_sf.toLocaleString()} SF` : ''} · {lease.lease_type || 'Unknown type'}</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline">Re-Upload PDF</Button>
          <Button className="bg-blue-600 hover:bg-blue-700" onClick={() => setShowSignature(true)}><Send className="w-4 h-4 mr-1" />Request Signature</Button>
          <Button className="bg-emerald-600 hover:bg-emerald-700" onClick={() => setShowApproval(true)}><CheckCircle2 className="w-4 h-4 mr-1" />Approve Lease</Button>
        </div>
      </div>

      {/* Low Confidence Block Alert */}
      {lowConf > 0 && (
        <div className="bg-red-50 border-2 border-red-300 rounded-xl p-4 flex items-center gap-3">
          <AlertTriangle className="w-6 h-6 text-red-500 flex-shrink-0" />
          <div>
            <p className="text-sm font-bold text-red-800">Budget Start Blocked — Low Confidence Fields Detected</p>
            <p className="text-xs text-red-600 mt-0.5">{lowConf} field(s) scored below 70% confidence. Human review and correction is required before this lease can be marked as "Budget Ready." Correct the flagged fields and re-validate.</p>
          </div>
        </div>
      )}

      {/* Confidence Summary */}
      <div className="grid grid-cols-4 gap-4">
        <Card className="bg-emerald-50 border-emerald-200"><CardContent className="p-4"><p className="text-[10px] font-semibold text-emerald-600 uppercase">High Confidence (≥90%)</p><p className="text-2xl font-bold text-emerald-700">{highConf} fields</p><p className="text-[10px] text-emerald-500">Auto-populated</p></CardContent></Card>
        <Card className="bg-amber-50 border-amber-200"><CardContent className="p-4"><p className="text-[10px] font-semibold text-amber-600 uppercase">Medium (70-89%)</p><p className="text-2xl font-bold text-amber-700">{medConf} fields</p><p className="text-[10px] text-amber-500">Flagged for review</p></CardContent></Card>
        <Card className="bg-red-50 border-red-200"><CardContent className="p-4"><p className="text-[10px] font-semibold text-red-600 uppercase">Low (&lt;70%) — BLOCKING</p><p className="text-2xl font-bold text-red-600">{lowConf} fields</p><p className="text-[10px] text-red-400">Must correct to proceed</p></CardContent></Card>
        <Card><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">Validation Checks</p><p className="text-2xl font-bold text-slate-900">{passCount}/{validationChecks.length} Pass</p><p className="text-[10px] text-amber-500">{validationChecks.length - passCount} warning(s)</p></CardContent></Card>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Left: Tabs with field groups */}
        <div className="lg:col-span-2">
          <Tabs defaultValue="Basic Terms">
            <TabsList className="bg-white border">
              {Object.keys(fields).map(tab => <TabsTrigger key={tab} value={tab} className="text-xs">{tab}</TabsTrigger>)}
            </TabsList>
            {Object.entries(fields).map(([tabName, fieldList]) => (
              <TabsContent key={tabName} value={tabName} className="mt-4 space-y-3">
                {fieldList.map((f, i) => (
                  <Card key={i} className={f.warning ? 'border-amber-200' : ''}>
                    <CardContent className="p-4 flex items-start justify-between">
                      <div>
                        <div className="flex items-center gap-2">
                          <p className="text-[10px] font-semibold text-slate-500 uppercase">{f.label}</p>
                          <Badge className={`text-[10px] ${confidenceColor(f.confidence)}`}>{f.confidence}%</Badge>
                        </div>
                        <p className="text-sm font-medium text-slate-900 mt-1">{String(f.value)}</p>
                        {f.warning && <p className="text-xs text-amber-600 mt-1 flex items-center gap-1"><AlertTriangle className="w-3 h-3" />{f.warning}</p>}
                      </div>
                      <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleFieldEdit(f)}><Pencil className="w-3.5 h-3.5 text-slate-400" /></Button>
                    </CardContent>
                  </Card>
                ))}
              </TabsContent>
            ))}
          </Tabs>
        </div>

        {/* Right: Validation + Allocation + Audit */}
        <div className="space-y-4">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-base">Validation Checks</CardTitle></CardHeader>
            <CardContent className="space-y-2">
              {validationChecks.map((c, i) => (
                <div key={i} className={`p-2.5 rounded-lg ${c.pass ? 'bg-emerald-50' : 'bg-red-50'}`}>
                  <div className="flex items-center gap-2">
                    {c.pass ? <CheckCircle2 className="w-3.5 h-3.5 text-emerald-500" /> : <AlertTriangle className="w-3.5 h-3.5 text-red-500" />}
                    <p className="text-xs font-medium text-slate-900">{c.label}</p>
                  </div>
                  <p className="text-[10px] text-slate-500 ml-5 mt-0.5">{c.detail}</p>
                </div>
              ))}
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-base">Allocation Settings</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              <div>
                <Label className="text-[10px] font-semibold text-slate-500 uppercase">Allocation Model</Label>
                <Select value={allocationModel} onValueChange={setAllocationModel}>
                  <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="pro_rata">Pro-Rata</SelectItem>
                    <SelectItem value="equal">Equal</SelectItem>
                    <SelectItem value="weighted">Weighted</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label className="text-[10px] font-semibold text-slate-500 uppercase">Vacancy Handling</Label>
                <Select value={vacancyHandling} onValueChange={setVacancyHandling}>
                  <SelectTrigger className="mt-1"><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="exclude">Exclude</SelectItem>
                    <SelectItem value="include">Include</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Request Signature Dialog */}
      <Dialog open={showSignature} onOpenChange={setShowSignature}>
        <DialogContent>
          <DialogHeader><DialogTitle>Request Digital Signature</DialogTitle></DialogHeader>
          <p className="text-sm text-slate-500">Send the lease for signature to a designated stakeholder. The magic link expires in 48 hours.</p>
          <div className="space-y-4 mt-2">
            <div>
              <Label>Send To</Label>
              <Select>
                <SelectTrigger><SelectValue placeholder="Select stakeholder" /></SelectTrigger>
                <SelectContent>
                  {stakeholders.map(s => <SelectItem key={s.id} value={s.id}>{s.name} ({s.role?.replace('_', ' ')})</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>Message (optional)</Label>
              <Textarea placeholder="Please review and sign the lease for Suite A-302..." rows={3} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowSignature(false)}>Cancel</Button>
            <Button className="bg-blue-600 hover:bg-blue-700">Send Request</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Approve Lease Dialog */}
      <Dialog open={showApproval} onOpenChange={setShowApproval}>
        <DialogContent>
          <DialogHeader><DialogTitle>Approve Lease</DialogTitle></DialogHeader>
          <p className="text-sm text-slate-500 mb-2">This will mark the lease as Budget-Ready</p>
          <div className="bg-slate-50 p-3 rounded-lg mb-2">
            <p className="text-sm font-medium text-slate-700">Lease Summary</p>
            <p className="text-xs text-slate-500">{lease.tenant_name} · {lease.lease_type} · {lease.start_date} to {lease.end_date}</p>
          </div>
          {validationChecks.some(c => !c.pass) && (
            <div className="flex items-center gap-2 text-amber-600 text-xs"><AlertTriangle className="w-3.5 h-3.5" />{validationChecks.filter(c => !c.pass).length} validation warning(s) — review before approving</div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowApproval(false)}>Cancel</Button>
            <Button className="bg-emerald-600 hover:bg-emerald-700" onClick={handleApprove} disabled={updateLeaseMutation.isPending}>
              {updateLeaseMutation.isPending && <Loader2 className="w-4 h-4 animate-spin mr-1" />}Confirm Approval
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      {/* Edit Field Dialog */}
      <Dialog open={!!editingField} onOpenChange={() => setEditingField(null)}>
        <DialogContent>
          <DialogHeader><DialogTitle>Edit: {editingField?.label}</DialogTitle></DialogHeader>
          <div className="space-y-3 py-2">
            <div>
              <Label>Current Value</Label>
              <p className="text-sm text-slate-500 mt-1">{editingField?.value}</p>
            </div>
            <div>
              <Label>New Value</Label>
              <Input value={editValue} onChange={e => setEditValue(e.target.value)} className="mt-1" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEditingField(null)}>Cancel</Button>
            <Button onClick={handleFieldSave} disabled={updateLeaseMutation.isPending} className="bg-blue-600 hover:bg-blue-700">
              {updateLeaseMutation.isPending && <Loader2 className="w-4 h-4 animate-spin mr-1" />}Save
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from "react";
import { leaseService } from "@/services/leaseService";
import { invokeLLM, uploadFile } from "@/services/integrations";
import useOrgId from "@/hooks/useOrgId";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Upload, FileText, CheckCircle2, Loader2, ArrowLeft, ArrowRight, Pencil, AlertTriangle } from "lucide-react";
import { Link } from "react-router-dom";
import { createPageUrl } from "@/utils";

export default function LeaseUpload() {
  const { orgId } = useOrgId();
  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [fileUrl, setFileUrl] = useState("");
  const [extractedData, setExtractedData] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [extracting, setExtracting] = useState(false);
  const [savedLeaseId, setSavedLeaseId] = useState(null);

  const handleFileSelect = async (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;
    setFile(selectedFile);
    setUploading(true);
    const { file_url } = await uploadFile({ file: selectedFile });
    setFileUrl(file_url);
    setUploading(false);
    setStep(2);

    // Start AI extraction
    setExtracting(true);
    const result = await invokeLLM({
      prompt: `Extract all lease terms from this commercial lease document. Be thorough and extract every possible field. Include confidence_scores (0-100) for each extracted field. Also extract:
- escalation_timing: "lease_anniversary" or "calendar_year"
- renewal_type: "new_lease", "option_letter", "auto_renew", or "none"
- renewal_notice_months: number of months notice required
- management_fee_basis: "cam_pool", "tenant_annual_rent", or "pro_rata_sf"
- percentage_rent_breakpoint: sales threshold before percentage rent applies
- sales_reporting_frequency: "monthly", "quarterly", or "annual"
- hvac_responsibility: "tenant", "landlord", or "shared"
- hvac_landlord_limit: max dollar amount landlord pays for HVAC
- lease_scope: "property" or "building"
- recon_deadline_days: days after year-end for reconciliation (default 90)
- recon_collection_limit_months: months landlord has to collect underpayments (default 12)
- cpi_index: CPI index source (e.g. CPI-U, CPI-W)`,
      file_urls: [file_url],
      response_json_schema: {
        type: "object",
        properties: {
          tenant_name: { type: "string" },
          lease_type: { type: "string" },
          start_date: { type: "string" },
          end_date: { type: "string" },
          base_rent: { type: "number" },
          rent_per_sf: { type: "number" },
          total_sf: { type: "number" },
          annual_rent: { type: "number" },
          escalation_type: { type: "string" },
          escalation_rate: { type: "number" },
          escalation_timing: { type: "string" },
          renewal_options: { type: "string" },
          renewal_type: { type: "string" },
          renewal_notice_months: { type: "number" },
          cam_cap_type: { type: "string" },
          cam_cap_rate: { type: "number" },
          cpi_index: { type: "string" },
          base_year: { type: "number" },
          gross_up_clause: { type: "boolean" },
          admin_fee_allowed: { type: "boolean" },
          admin_fee_pct: { type: "number" },
          management_fee_pct: { type: "number" },
          management_fee_basis: { type: "string" },
          free_rent_months: { type: "string" },
          ti_allowance: { type: "number" },
          percentage_rent: { type: "boolean" },
          percentage_rent_rate: { type: "number" },
          percentage_rent_breakpoint: { type: "number" },
          sales_reporting_frequency: { type: "string" },
          hvac_responsibility: { type: "string" },
          hvac_landlord_limit: { type: "number" },
          lease_scope: { type: "string" },
          recon_deadline_days: { type: "number" },
          recon_collection_limit_months: { type: "number" },
          confidence_scores: { type: "object" }
        }
      }
    });
    setExtractedData(result);
    setExtracting(false);
    setStep(3);
  };

  const saveLease = async () => {
    if (!extractedData) return;
    // Check for low confidence fields - block budget if any field < 70%
    const scores = extractedData.confidence_scores || {};
    const hasLowConf = Object.values(scores).some(s => typeof s === 'number' && s < 70);
    const avgConf = Object.values(scores).filter(s => typeof s === 'number');
    const overallConf = avgConf.length > 0 ? Math.round(avgConf.reduce((a, b) => a + b, 0) / avgConf.length) : 85;

    const { confidence_scores, ...leaseFields } = extractedData;
    const newLease = await leaseService.create({
      ...leaseFields,
      pdf_url: fileUrl,
      status: "extracted",
      confidence_score: overallConf,
      low_confidence_block: hasLowConf,
      extraction_data: { confidence_scores: scores },
      version: 1,
      org_id: orgId || ""
    });
    setSavedLeaseId(newLease.id);
    setStep(4);
  };

  const steps = [
    { num: 1, label: "Upload PDF" },
    { num: 2, label: "AI Extraction" },
    { num: 3, label: "Review Fields" },
    { num: 4, label: "Validate & Sign" },
  ];

  const confidenceColor = (score) => {
    if (score >= 90) return "text-emerald-600 bg-emerald-50";
    if (score >= 75) return "text-amber-600 bg-amber-50";
    return "text-red-600 bg-red-50";
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <Link to={createPageUrl("Leases")} className="text-sm text-slate-500 hover:text-slate-700 flex items-center gap-1">
        <ArrowLeft className="w-4 h-4" /> Back to Leases
      </Link>

      {/* Step indicator */}
      <div className="flex items-center gap-2">
        {steps.map((s, i) => (
          <React.Fragment key={s.num}>
            <div className="flex items-center gap-2">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${step >= s.num ? 'bg-emerald-500 text-white' : 'bg-slate-200 text-slate-500'}`}>
                {step > s.num ? <CheckCircle2 className="w-4 h-4" /> : s.num}
              </div>
              <span className={`text-sm font-medium ${step >= s.num ? 'text-slate-900' : 'text-slate-400'}`}>{s.label}</span>
            </div>
            {i < steps.length - 1 && <div className={`flex-1 h-0.5 ${step > s.num ? 'bg-emerald-500' : 'bg-slate-200'}`} />}
          </React.Fragment>
        ))}
      </div>

      {/* Step 1: Upload */}
      {step === 1 && (
        <Card>
          <CardContent className="p-12 text-center">
            <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4">
              <Upload className="w-8 h-8 text-slate-400" />
            </div>
            <h2 className="text-xl font-bold text-slate-900 mb-2">Upload Lease PDF</h2>
            <p className="text-slate-500 text-sm mb-6">Drag and drop your lease PDF here, or click to browse.<br />Our AI will extract all key lease terms automatically.</p>
            <label>
              <input type="file" accept=".pdf" className="hidden" onChange={handleFileSelect} />
              <Button asChild className="bg-[#1a2744] hover:bg-[#243b67] cursor-pointer">
                <span>{uploading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}Browse Files</span>
              </Button>
            </label>
            <p className="text-xs text-slate-400 mt-3">Supports PDF up to 50MB</p>
          </CardContent>
        </Card>
      )}

      {/* Step 2: Extracting */}
      {step === 2 && (
        <Card>
          <CardContent className="p-12 text-center">
            <Loader2 className="w-12 h-12 animate-spin text-blue-600 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-slate-900 mb-2">AI Extraction in Progress</h2>
            <p className="text-slate-500 text-sm">Analyzing lease document and extracting key terms...</p>
            <p className="text-xs text-slate-400 mt-2">{file?.name}</p>
          </CardContent>
        </Card>
      )}

      {/* Step 3: Review */}
      {step === 3 && extractedData && (
        <div className="grid lg:grid-cols-2 gap-6">
          <Card>
            <CardContent className="p-4">
              <div className="bg-slate-100 rounded-lg p-8 min-h-[500px] flex items-center justify-center">
                <div className="text-center">
                  <FileText className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                  <p className="text-sm text-slate-400">{file?.name}</p>
                  <p className="text-xs text-slate-300 mt-1">PDF Preview</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-bold text-slate-900">Extraction Results</h2>
              <div className="flex gap-2 text-xs">
                <Badge className="bg-emerald-50 text-emerald-700">10 high</Badge>
                <Badge className="bg-amber-50 text-amber-700">3 medium</Badge>
                <Badge className="bg-red-50 text-red-700">1 low</Badge>
              </div>
            </div>
            {Object.entries(extractedData).filter(([k]) => k !== 'confidence_scores').map(([key, value]) => (
              <Card key={key} className="border">
                <CardContent className="p-4 flex items-start justify-between">
                  <div>
                    <div className="flex items-center gap-2">
                      <p className="text-[10px] font-semibold text-slate-500 uppercase">{key.replace(/_/g, ' ')}</p>
                      <Badge className={`text-[10px] ${confidenceColor(extractedData.confidence_scores?.[key] || 85)}`}>
                        {extractedData.confidence_scores?.[key] || 85}%
                      </Badge>
                    </div>
                    <p className="text-sm font-medium text-slate-900 mt-1">{value === true ? 'Yes' : value === false ? 'No' : String(value || '—')}</p>
                  </div>
                  <Button variant="ghost" size="icon" className="h-8 w-8"><Pencil className="w-3.5 h-3.5" /></Button>
                </CardContent>
              </Card>
            ))}
            <div className="flex gap-3 pt-4">
              <Button variant="outline" onClick={() => setStep(1)}>Re-upload PDF</Button>
              <Button onClick={saveLease} className="flex-1 bg-[#1a2744] hover:bg-[#243b67]">Proceed to Validation <ArrowRight className="w-4 h-4 ml-2" /></Button>
            </div>
          </div>
        </div>
      )}

      {/* Step 4: Validation */}
      {step === 4 && (
        <Card>
          <CardContent className="p-8 text-center">
            <CheckCircle2 className="w-16 h-16 text-emerald-500 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-slate-900 mb-2">Lease Saved Successfully</h2>
            <p className="text-slate-500 text-sm mb-4">The lease has been extracted and saved. You can now review and validate it.</p>
            {extractedData?.confidence_scores && Object.values(extractedData.confidence_scores).some(s => typeof s === 'number' && s < 70) && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 mb-6 flex items-center gap-3 text-left max-w-lg mx-auto">
                <AlertTriangle className="w-5 h-5 text-red-500 flex-shrink-0" />
                <div>
                  <p className="text-sm font-semibold text-red-800">Low Confidence Fields Detected</p>
                  <p className="text-xs text-red-600 mt-0.5">Budget start is blocked until a human reviews and corrects the flagged fields. Open the Lease Review to resolve.</p>
                </div>
              </div>
            )}
            <div className="flex gap-3 justify-center">
              <Link to={createPageUrl("Leases")}><Button variant="outline">Back to Leases</Button></Link>
              <Link to={createPageUrl("LeaseReview") + (savedLeaseId ? `?id=${savedLeaseId}` : '')}><Button className="bg-[#1a2744]">Review & Validate</Button></Link>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Building2, Loader2, Mail, ArrowRight, AlertCircle, Lock, Eye, EyeOff, CheckCircle2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { createPageUrl } from "@/utils";
import { useAuth } from "@/lib/AuthContext";
import { supabase } from "@/services/supabaseClient";
import { verifyAccessRequest } from "@/services/api";

export default function Login() {
  const navigate = useNavigate();
  const { login, loginWithGoogle } = useAuth();

  const [view, setView] = useState("login"); // "login" | "create"
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Registration specifics
  const [fullName, setFullName] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [verifiedCompany, setVerifiedCompany] = useState(null);
  const [verifiedRole, setVerifiedRole] = useState(null);
  const [isValidatingEmail, setIsValidatingEmail] = useState(false);
  const [registrationSuccess, setRegistrationSuccess] = useState(false);
  const [loginVerifiedCompany, setLoginVerifiedCompany] = useState(null);
  const [loginEmailChecked, setLoginEmailChecked] = useState(false);

  const resetForm = () => {
    setError("");
    setPassword("");
    setConfirmPassword("");
    setFullName("");
    setEmail("");
    setVerifiedCompany(null);
    setVerifiedRole(null);
    setLoginVerifiedCompany(null);
    setLoginEmailChecked(false);
  };

  const handleEmailLogin = async (e) => {
    e.preventDefault();
    if (!email) { setError("Please enter your email."); return; }
    if (!password) { setError("Please enter your password."); return; }

    setError("");
    setLoading(true);
    try {
      await login(email, password);
      navigate("/");
    } catch (err) {
      console.error("[DEBUG LOGIN ERROR]:", err);
      setError(err.message || "Invalid email or password.");
    }
    setLoading(false);
  };



  const validateApprovedEmail = async (emailToCheck) => {
    if (!emailToCheck) {
      setVerifiedCompany(null);
      setVerifiedRole(null);
      return false;
    }

    setIsValidatingEmail(true);
    setError("");
    try {
      const res = await verifyAccessRequest(emailToCheck);
      if (res && res.valid) {
        setVerifiedCompany(res.company_name);
        setVerifiedRole(res.role || "Admin (Owner)");
        setIsValidatingEmail(false);
        return true;
      } else {
        setVerifiedCompany(null);
        setVerifiedRole(null);
        setError(res?.message || "Your email is not approved for account creation.");
        setIsValidatingEmail(false);
        return false;
      }
    } catch (err) {
      setVerifiedCompany(null);
      setVerifiedRole(null);
      setError("Failed to verify access request. Please try again.");
      setIsValidatingEmail(false);
      return false;
    }
  };

  const handleEmailBlur = async () => {
    if (view === "create" && email && !verifiedCompany) {
      await validateApprovedEmail(email);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    if (!fullName) { setError("Please enter your full name."); return; }
    if (!password) { setError("Please enter a password."); return; }
    if (password !== confirmPassword) { setError("Passwords do not match."); return; }

    if (!verifiedCompany) {
      const isValid = await validateApprovedEmail(email);
      if (!isValid) return;
    }

    // Password rules
    const hasUpper = /[A-Z]/.test(password);
    const hasNumber = /[0-9]/.test(password);
    const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);
    if (password.length < 8 || !hasUpper || !hasNumber || !hasSpecial) {
      setError("Password must be at least 8 characters and include uppercase, number, and special character.");
      return;
    }

    setError("");
    setLoading(true);
    try {
      const { data, error: signUpError } = await supabase.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: window.location.origin,
          data: {
            full_name: fullName,
            onboarding_type: (verifiedRole && verifiedRole.startsWith('Admin')) ? 'owner' : 'member'
          }
        }
      });
      if (signUpError) throw signUpError;

      // If we got a session (email confirmation is off), user is already logged in at aal1.
      // We still show the success screen to inform them what's next.
      setRegistrationSuccess(true);
    } catch (err) {
      setError(err.message || "Failed to create account.");
    }
    setLoading(false);
  };

  const handleGoogleLogin = async () => {
    setLoading(true);
    setError("");
    try {
      await loginWithGoogle();
    } catch (err) {
      setError(err.message || "Failed to sign in with Google.");
      setLoading(false);
    }
  };

  // ─── Account Creation Success ────────────────────────────
  if (registrationSuccess) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full text-center">
          <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-blue-100 flex items-center justify-center">
             <Mail className="w-10 h-10 text-blue-600" />
          </div>
          <h2 className="text-2xl font-bold text-slate-900 mb-2">Check your email!</h2>
          <p className="text-slate-500 text-sm mb-6 leading-relaxed">
            We've sent a confirmation link to <strong>{email}</strong>. Once you click it, you'll be redirected back here to set up your security MFA.
          </p>
          <p className="text-slate-400 text-xs italic">
            Please keep this window open while you verify your email.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50 flex flex-col">
      {/* Top Bar */}
      <div className="px-6 py-5 flex items-center justify-between max-w-6xl mx-auto w-full">
        <Link to={createPageUrl("Landing")} className="flex items-center gap-2.5">
          <div className="w-8 h-8 bg-[#1a2744] rounded-lg flex items-center justify-center">
             <Building2 className="w-4.5 h-4.5 text-white" />
          </div>
          <span className="text-[#1a2744] font-bold text-lg tracking-tight">CRE Suite</span>
        </Link>
        <Link to={createPageUrl("RequestAccess")} className="text-sm text-slate-500 hover:text-slate-700 font-medium transition-colors">
          Request Access <ArrowRight className="inline w-3.5 h-3.5" />
        </Link>
      </div>

      {/* Main */}
      <div className="flex-1 flex items-center justify-center px-4 pb-16">
        <div className="max-w-[420px] w-full">
          <div className="text-center mb-8">
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight mb-2">
              {view === "create" ? "Create your account" : "Welcome back"}
            </h1>
            <p className="text-slate-500 text-sm">
              {view === "create" ? "Complete your approved registration" : "Sign in to your CRE Suite account"}
            </p>
          </div>

          <div className="bg-white rounded-2xl border border-slate-200/80 shadow-sm p-8">
            {/* Google Login (Only for Sign In view) */}
            {view === "login" && (
              <>
                <div className="mb-6">
                  <button
                    type="button"
                    onClick={handleGoogleLogin}
                    disabled={loading}
                    className="w-full h-12 rounded-xl border border-slate-200 bg-white hover:bg-slate-50 flex items-center justify-center gap-3 text-sm font-medium text-slate-700 transition-all hover:border-slate-300 hover:shadow-sm disabled:opacity-50"
                  >
                    <svg className="w-5 h-5" viewBox="0 0 24 24">
                      <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/>
                      <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                      <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                      <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
                    </svg>
                    Continue with Google
                  </button>
                </div>
                <div className="flex items-center gap-4 mb-6">
                  <div className="flex-1 h-px bg-slate-200" />
                  <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">or continue with email</span>
                  <div className="flex-1 h-px bg-slate-200" />
                </div>
              </>
            )}

            {/* Form */}
            <form onSubmit={view === "create" ? handleRegister : handleEmailLogin} className="space-y-4">

              {/* Login View */}
              {view === "login" && (
                <div className="space-y-4 animate-in fade-in duration-300">
                  <div>
                    <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Email</Label>
                    <div className="relative mt-1.5">
                      <Mail className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                      <Input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        placeholder="you@company.com"
                        className="h-11 pl-10"
                      />
                    </div>
                  </div>
                  <div>
                    <div className="flex items-center justify-between mt-4">
                      <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Password</Label>
                      <button type="button" className="text-[11px] text-blue-600 hover:text-blue-700 font-medium">Forgot password?</button>
                    </div>
                    <div className="relative mt-1.5">
                      <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                      <Input
                        type={showPassword ? "text" : "password"}
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="••••••••"
                        className="h-11 pl-10 pr-10"
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                      >
                        {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </button>
                    </div>
                  </div>
                </div>
              )}

              {/* Create Account View */}
              {view === "create" && (
                <div className="space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                  <div>
                    <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Full Name</Label>
                    <Input
                      type="text"
                      className="mt-1.5 h-11"
                      value={fullName}
                      onChange={(e) => setFullName(e.target.value)}
                      placeholder="Jane Doe"
                      required
                    />
                  </div>

                  <div>
                    <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Email</Label>
                    <div className="relative mt-1.5">
                      <Mail className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                      <Input
                        type="email"
                        value={email}
                        onChange={(e) => { 
                          setEmail(e.target.value); 
                          setError(""); 
                          setVerifiedCompany(null); 
                        }}
                        onBlur={handleEmailBlur}
                        placeholder="you@company.com"
                        className="h-11 pl-10"
                      />
                      {isValidatingEmail && (
                        <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-slate-400" />
                      )}
                      {verifiedCompany && (
                        <CheckCircle2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-emerald-500" />
                      )}
                    </div>
                  </div>

                  <div>
                    <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Password</Label>
                    <div className="relative mt-1.5">
                      <Input
                        type={showPassword ? "text" : "password"}
                        className="h-11 pr-10"
                        value={password}
                        onChange={(e) => { setPassword(e.target.value); setError(""); }}
                        placeholder="••••••••"
                        required
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                      >
                        {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                      </button>
                    </div>
                  </div>
                  <div>
                    <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">Confirm Password</Label>
                    <Input
                      type={showPassword ? "text" : "password"}
                      className="mt-1.5 h-11"
                      value={confirmPassword}
                      onChange={(e) => { setConfirmPassword(e.target.value); setError(""); }}
                      placeholder="••••••••"
                      required
                    />
                  </div>

                  {password && (password.length < 8 || !/[A-Z]/.test(password) || !/[0-9]/.test(password) || !/[!@#$%^&*(),.?":{}|<>]/.test(password)) && (
                    <div className="bg-red-50 p-3 rounded-lg border border-red-100 flex gap-2 items-start mt-2">
                       <AlertCircle className="w-4 h-4 text-red-600 mt-0.5 flex-shrink-0" />
                       <p className="text-[11px] text-red-600 leading-relaxed font-medium">
                         Password must contain at least 8 characters, 1 uppercase letter, 1 number, and 1 special character.
                       </p>
                    </div>
                  )}

                  <div className="grid grid-cols-2 gap-3 pt-2">
                    <div>
                      <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider flex items-center justify-between">
                        Company Name
                      </Label>
                      <Input
                        type="text"
                        className="mt-1.5 h-11 bg-slate-50 text-slate-700 placeholder:text-slate-400"
                        value={verifiedCompany || ""}
                        placeholder="Auto-detected"
                        readOnly
                        disabled={!verifiedCompany}
                      />
                    </div>
                    <div>
                      <Label className="text-slate-700 text-xs font-semibold uppercase tracking-wider">
                        Role
                      </Label>
                      <Input
                        type="text"
                        className="mt-1.5 h-11 bg-slate-50 text-slate-700 placeholder:text-slate-400"
                        value={verifiedRole || ""}
                        placeholder="Auto-detected"
                        readOnly
                        disabled={!verifiedRole}
                      />
                    </div>
                  </div>
                </div>
              )}

              {error && (
                <div className="flex items-center gap-2 text-sm text-red-600 bg-red-50 border border-red-100 rounded-lg p-3">
                  <AlertCircle className="w-4 h-4 flex-shrink-0" />
                  <span>{error}</span>
                </div>
              )}

              {/* Company not verified warning */}
              {view === "create" && !verifiedCompany && email && !isValidatingEmail && !error && (
                <div className="flex items-center gap-2 text-sm text-amber-700 bg-amber-50 border border-amber-100 rounded-lg p-3">
                  <AlertCircle className="w-4 h-4 flex-shrink-0 text-amber-600" />
                  <span>Enter your approved email to auto-detect your company. Only approved applicants can create an account.</span>
                </div>
              )}

              <Button
                type="submit"
                disabled={loading || isValidatingEmail || (view === "create" && !verifiedCompany)}
                title={view === "create" && !verifiedCompany ? "Your email must be approved before creating an account" : undefined}
                className={`w-full h-12 font-semibold rounded-xl shadow-sm gap-2 text-sm transition-colors mt-6 ${
                  view === "create" ? "bg-emerald-600 hover:bg-emerald-700 text-white disabled:opacity-40" : "bg-[#1a2744] hover:bg-[#243b67] text-white"
                }`}
              >
                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
                {view === "create" ? "Create Account" : "Sign In"}
              </Button>
            </form>
          </div>

          <div className="text-center mt-6">
             {view === "login" ? (
               <p className="text-sm text-slate-500 font-medium">
                 Don't have an account?{" "}
                 <button 
                   onClick={() => { setView("create"); resetForm(); }}
                   className="text-emerald-600 hover:text-emerald-700 font-semibold"
                 >
                   Create Account
                 </button>
               </p>
             ) : (
               <p className="text-sm text-slate-500 font-medium">
                 Already have an account?{" "}
                 <button 
                   onClick={() => { setView("login"); resetForm(); }}
                   className="text-blue-600 hover:text-blue-700 font-semibold"
                 >
                   Sign In
                 </button>
               </p>
             )}
          </div>

          <p className="text-center text-[11px] text-slate-400 mt-6">
            Protected by enterprise-grade security. <a href="#" className="text-blue-500 hover:underline">Privacy</a> · <a href="#" className="text-blue-500 hover:underline">Terms</a>
          </p>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { OrganizationService } from "@/services/api";
import { updateProfile, redirectToLogin } from "@/services/auth";
import { useAuth } from "@/lib/AuthContext";
import { logAudit } from "@/services/audit";
import { supabase } from "@/services/supabaseClient";
import { Building2, CheckCircle2, ArrowRight, ArrowLeft, Loader2, CreditCard, FileText, Lock, Clock, Shield, AlertCircle, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { createPageUrl } from "@/utils";

const steps = [
  { id: 1, label: "Company Setup", icon: Building2 },
  { id: 2, label: "Agreement", icon: FileText },
  { id: 3, label: "Payment", icon: CreditCard },
  { id: 4, label: "Confirmation", icon: CheckCircle2 },
];

export default function Onboarding() {
  const { user: authUser, refreshProfile, logout, isLoadingAuth } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const step = parseInt(searchParams.get('step') || '1', 10);
  const setStep = (newStep) => {
    setSearchParams({ step: newStep.toString() });
  };
  const [user, setUser] = useState(null);
  const [org, setOrg] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    name: "", address: "", phone: "", timezone: "America/New_York",
    currency: "USD", primary_contact_email: "", plan: "professional",
    industry: "commercial_re"
  });

  useEffect(() => {
    // Wait for auth context to finish loading before doing anything
    if (isLoadingAuth) {
      console.log('[Onboarding] Auth still loading, waiting...');
      return;
    }

    const init = async () => {
      try {
        if (!authUser) {
          console.log('[Onboarding] No authenticated user, redirecting to login');
          redirectToLogin(createPageUrl("Onboarding"));
          setLoading(false);
          return;
        }

        setUser(authUser);
        setForm(f => ({ ...f, primary_contact_email: authUser.email || "" }));

        // Find existing org using the user's membership org_id
        if (authUser.org_id) {
          console.log('[Onboarding] Initializing with Org:', authUser.org_id);
          
          await new Promise(r => setTimeout(r, 600));

          const orgData = await OrganizationService.get(authUser.org_id);
          console.log('[Onboarding] Org data fetched:', { found: !!orgData, status: orgData?.status, step: orgData?.onboarding_step });
          if (orgData) {
            setOrg(orgData);
            
            const serverStep = orgData.onboarding_step || 1;
            const currentUrlStep = parseInt(searchParams.get('step'), 10);
            
            if (!currentUrlStep && serverStep > 1) {
              console.log('[Onboarding] Syncing to server step:', serverStep);
              setStep(serverStep);
            }
            
            // If already active, we don't need to be here, but don't hard redirect 
            // inside init as it leads to loops if the router isn't ready.
            // App.jsx will handle the high-level redirection.
          }
        }
      } catch (e) {
        console.error('[Onboarding] init error:', e);
      } finally {
        setLoading(false);
      }
    };
    init();

  }, [authUser]);

  // Status Polling: Automatically check for approval while on Step 4
  useEffect(() => {
    if (step !== 4) return;
    console.log('[Onboarding] Status polling active (10s interval)');
    const checkApproval = async () => {
      try {
        if (org?.id) {
          const latestOrg = await OrganizationService.get(org.id);
          if (latestOrg?.status === 'active') {
            console.log('[Onboarding] Approval detected via org! Refreshing profile...');
            await refreshProfile();
            return;
          }
        }
        const p = await refreshProfile();
        if (p?.profile?.status === 'active' || p?.status === 'active') {
          console.log('[Onboarding] Approval detected via profile! Redirecting...');
          // Let App.jsx handle the specific target (WelcomeAboard or Dashboard)
        }
      } catch (e) {
        console.error('[Onboarding] Poll error:', e);
      }

    };
    checkApproval();
    const interval = setInterval(checkApproval, 10000);
    return () => clearInterval(interval);
  }, [step, refreshProfile, org?.id]);

  const saveCompanyInfo = async () => {
    console.log('[Onboarding] saveCompanyInfo started', { name: !!form.name, email: !!form.primary_contact_email });
    if (!form.name || !form.primary_contact_email) {
      setSaving('val_error');
      try {
        const { toast } = await import("sonner");
        toast.error("Organization Name and Primary Email are required to continue.");
      } catch (e) {}
      return;
    }
    
    setSaving(true);
    const { toast } = await import("sonner");
    const loadingToast = toast.loading("Saving company information...");
    
    try {
      let savedOrg;
      if (org) {
        console.log('[Onboarding] Updating existing org:', org.id);
        savedOrg = await OrganizationService.update(org.id, { ...form, onboarding_step: 2 });
      } else {
        // Fallback: This should rarely happen if first-login worked
        console.warn('[Onboarding] Org missing, attempting fresh create');
        savedOrg = await OrganizationService.create({ ...form, status: "onboarding", onboarding_step: 2 });
        
        if (savedOrg?.id && authUser?.id && supabase) {
          await supabase.from('memberships').upsert({
            user_id: authUser.id,
            org_id: savedOrg.id,
            role: 'org_admin',
          }, { onConflict: 'user_id,org_id' });
          await refreshProfile();
        }
      }
      
      console.log('[Onboarding] Save success, moving to step 2');
      setOrg(savedOrg);
      setStep(2);
      toast.success("Company information saved!", { id: loadingToast });
    } catch (e) {
      console.error('[Onboarding] save error:', e);
      toast.error(e.message || "Failed to save company information", { id: loadingToast });
    } finally {
      setSaving(false);
    }
  };
 // Called when the final step (Confirmation) is reached
  const completeOnboarding = async () => {
    try {
      // Advance step visually
      if (org) {
        await OrganizationService.update(org.id, { onboarding_step: 4 });
      }

      console.log('[Onboarding] Triggering complete-onboarding Edge Function');
      const { data, error } = await supabase.functions.invoke('complete-onboarding');
      
      if (error || data?.error) {
         throw new Error(error?.message || data?.error || 'Failed to complete onboarding');
      }

      // Audit log â€” onboarding completion
      await logAudit({
        entityType: 'Profile',
        entityId: authUser?.id,
        action: 'update',
        fieldChanged: 'onboarding_status',
        oldValue: 'onboarding',
        newValue: 'under_review',
        orgId: org?.id,
        userId: authUser?.id,
        userEmail: authUser?.email,
      }).catch(() => {});

      // Refresh the auth context so App.jsx picks up `under_review`
      await refreshProfile();
    } catch (e) {
      console.error('[Onboarding] complete error:', e);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="w-8 h-8 animate-spin text-slate-400 mx-auto mb-3" />
          <p className="text-sm text-slate-400">Loading your account...</p>
