import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { AccessRequestService, OrganizationService } from "@/services/api";
import { useAuth } from "@/lib/AuthContext";

import { supabase } from "@/services/supabaseClient";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogTrigger } from "@/components/ui/dialog";
import { Shield, Users, Search, Download, CheckCircle2, X, Loader2, Package, Trash2, Mail } from "lucide-react";
import { Checkbox } from "@/components/ui/checkbox";
import { ALL_MODULE_KEYS, MODULE_DEFINITIONS } from "@/lib/moduleConfig";

export default function SuperAdmin() {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [selectedModules, setSelectedModules] = useState([]);
  const [inviteEmail, setInviteEmail] = useState("");
  const [processingRequests, setProcessingRequests] = useState(new Set());
  const [selectedRequests, setSelectedRequests] = useState(new Set());
  const [inviting, setInviting] = useState(false);
  const [inviteSuccess, setInviteSuccess] = useState(false);
  const [activeTab, setActiveTab] = useState("access");

  // Platform Admin Invite State
  const [showPlatformInviteModal, setShowPlatformInviteModal] = useState(false);
  const [platformInviteEmail, setPlatformInviteEmail] = useState("");
  const [platformInviting, setPlatformInviting] = useState(false);

  const [editingOrgModules, setEditingOrgModules] = useState(null);
  const authChecked = !!user || true;

  const { data: platformAdmins = [], isLoading: isLoadingAdmins } = useQuery({
    queryKey: ['platform-admins'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("memberships")
        .select("id, user_id, role, profiles(id, email, full_name)")
        .eq("role", "super_admin");
      if (error) throw error;
      return (data || []).map(m => ({
        membership_id: m.id,
        user_id: m.user_id,
        email: m.profiles?.email || "—",
        full_name: m.profiles?.full_name || "—",
        role: "super_admin"
      }));
    },
    enabled: authChecked,
  });

  const handleInvitePlatformAdmin = async () => {
    if (!platformInviteEmail) return;
    setPlatformInviting(true);
    try {
      const { data: result, error: fnError } = await supabase.functions.invoke('invite-user', {
        body: { email: platformInviteEmail, role: "super_admin", onboarding_type: "invited" }
      });

      if (fnError) throw new Error(fnError.message || "invite-user failed");

      const { toast } = await import("sonner");
      toast.success("Platform admin invited successfully!");
      setShowPlatformInviteModal(false);
      setPlatformInviteEmail("");
      queryClient.invalidateQueries({ queryKey: ['platform-admins'] });
    } catch(e) {
      console.error('Invite error:', e);
      const { toast } = await import("sonner");
      toast.error(e.message || "Failed to invite platform admin");
    }
    setPlatformInviting(false);
  };

  const handleInviteClient = async () => {
    if (!inviteEmail) return;
    setInviting(true);
    try {
      const { data: result, error: fnError } = await supabase.functions.invoke('invite-client', {
        body: { 
          email: inviteEmail, 
          role: "org_admin", 
          onboarding_type: "owner" // Important: owners go through onboarding
        }
      });

      if (fnError) throw new Error(fnError.message || "Failed to send invitation");
      setInviteSuccess(true);
    } catch(e) { 
      console.error('Invite error:', e);
      const { toast } = await import("sonner");
      toast.error(e.message || "Failed to send invitation");
    }
    setInviting(false);
  };

  const { data: requests = [], isLoading } = useQuery({
    queryKey: ['access-requests', activeTab],
    queryFn: () => AccessRequestService.list('-created_at'),
    enabled: authChecked && user?.role === 'admin',
    refetchOnWindowFocus: false,
  });

  const { data: orgs = [] } = useQuery({
    queryKey: ['organizations'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('organizations')
        .select(`
          *,
          memberships(
            role,
            profiles(
              email
            )
          )
        `)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data.map(org => ({
        ...org,
        // Helper to get the primary admin email
        admin_email: org.memberships?.find(m => m.role === 'org_admin')?.profiles?.email || 
                     org.memberships?.[0]?.profiles?.email || 
                     org.primary_contact_email
      }));
    },
    enabled: authChecked && user?.role === 'admin',
  });

  const updateRequest = useMutation({
    mutationFn: async ({ id, approved }) => {
      const { data: result, error: fnError } = await supabase.functions.invoke('approve-request-v2', {
        body: { id, approved }
      });
      if (fnError) throw new Error(fnError.message || 'Action failed');
      return result;
    },
    onMutate: ({ id }) => {
      setProcessingRequests(prev => new Set(prev).add(id));
    },
    onSettled: (data, error, { id }) => {
      setProcessingRequests(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
      if (error) {
        console.error('Mutation error:', error);
        import('sonner').then(({ toast }) => {
          const msg = error.message || 'Action failed';
          toast.error(msg, {
            description: "Check console for more details if this persists."
          });
        });
      }
      queryClient.invalidateQueries({ queryKey: ['access-requests'] });
    },
  });

  // Revoke action: sets approved user back to pending_approval
  const revokeRequest = useMutation({
    mutationFn: async ({ id, email }) => {
      // Update access_request status
      const { error: reqError } = await supabase
        .from('access_requests')
        .update({ status: 'pending_approval', updated_at: new Date().toISOString() })
        .eq('id', id);
      if (reqError) throw reqError;

      // Also revert the profile status if they have one
      if (email) {
        const { error: profError } = await supabase
          .from('profiles')
          .update({ status: 'pending_approval' })
          .eq('email', email);
        if (profError) console.warn('[Revoke] Profile update warning:', profError.message);
      }

      return { id };
    },
    onMutate: ({ id }) => {
      setProcessingRequests(prev => new Set(prev).add(id));
    },
    onSettled: (data, error, { id }) => {
      setProcessingRequests(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
      if (error) {
        import('sonner').then(({ toast }) => toast.error(error.message || 'Revoke failed'));
      } else {
        import('sonner').then(({ toast }) => toast.success('Access revoked. User must be re-approved.'));
      }
      queryClient.invalidateQueries({ queryKey: ['access-requests'] });
    },
  });

  const deleteRequest = useMutation({
    mutationFn: async (id) => {
      const success = await AccessRequestService.delete(id);
      if (!success) throw new Error('Deletion failed');
      return id;
    },
    onMutate: (id) => {
      setProcessingRequests(prev => new Set(prev).add(id));
    },
    onSettled: (data, error, id) => {
      setProcessingRequests(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
      if (error) {
        import('sonner').then(({ toast }) => toast.error(error.message || 'Failed to delete request'));
      } else {
        import('sonner').then(({ toast }) => toast.success('Request deleted permanently'));
      }
      queryClient.invalidateQueries({ queryKey: ['access-requests'] });
    },
  });

  const handleBulkDelete = () => {
    if (selectedRequests.size === 0) return;
    if (window.confirm(`Are you sure you want to delete ${selectedRequests.size} requests?`)) {
      setProcessingRequests(prev => new Set([...prev, ...selectedRequests]));
      Promise.all(Array.from(selectedRequests).map(id => AccessRequestService.delete(id)))
        .then(() => {
          import('sonner').then(({ toast }) => toast.success(`Deleted ${selectedRequests.size} requests`));
          setSelectedRequests(new Set());
          queryClient.invalidateQueries({ queryKey: ['access-requests'] });
        })
        .catch(() => {
          import('sonner').then(({ toast }) => toast.error('Failed to delete some requests'));
        })
        .finally(() => {
          setProcessingRequests(prev => {
            const next = new Set(prev);
            selectedRequests.forEach(id => next.delete(id));
            return next;
          });
        });
    }
  };

  const toggleSelectAllList = (checked, list) => {
    if (checked) {
      const next = new Set(selectedRequests);
      list.forEach(r => next.add(r.id));
      setSelectedRequests(next);
    } else {
      const next = new Set(selectedRequests);
      list.forEach(r => next.delete(r.id));
      setSelectedRequests(next);
    }
  };

  const toggleSelect = (id, checked) => {
    setSelectedRequests(prev => {
      const next = new Set(prev);
      if (checked) next.add(id);
      else next.delete(id);
      return next;
    });
  };

  const accessReqs = requests.filter(r => r.request_type !== 'demo' && r.request_type !== 'contact');
  const demoReqs = requests.filter(r => r.request_type === 'demo');
  const contactReqs = requests.filter(r => r.request_type === 'contact');

  const pendingCount = requests.filter(r => r.status === 'pending_approval').length;
  const pendingAccessCount = accessReqs.filter(r => r.status === 'pending_approval').length;
  const pendingDemoCount = demoReqs.filter(r => r.status === 'pending_approval').length;
  const pendingContactCount = contactReqs.filter(r => r.status === 'pending_approval').length;

  if (!authChecked) {
    return (
      <div className="flex items-center justify-center h-96">
        <Loader2 className="w-8 h-8 animate-spin text-slate-400" />
      </div>
    );
  }

  if (!user || user.role !== "admin") {
    return (
      <div className="flex flex-col items-center justify-center h-96 text-center px-4">
        <div className="w-16 h-16 bg-red-100 rounded-2xl flex items-center justify-center mb-4">
          <Shield className="w-8 h-8 text-red-500" />
        </div>
        <h2 className="text-2xl font-bold text-slate-900 mb-2">Access Denied</h2>
        <p className="text-slate-500 max-w-md">The SuperAdmin Console is restricted to platform administrators only. If you believe this is an error, contact your system administrator.</p>
      </div>
    );
  }

  const renderRequestTable = (list, title, countPending, type) => (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle className="text-base">{title}</CardTitle>
          <p className="text-xs text-slate-400">{countPending} pending</p>
        </div>
        <div className="flex gap-2">
          {selectedRequests.size > 0 && (
            <Button variant="destructive" size="sm" onClick={handleBulkDelete}>
              <Trash2 className="w-4 h-4 mr-1" />
              Delete Selected ({selectedRequests.size})
            </Button>
          )}
          <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" /><Input placeholder="Search..." className="pl-9 w-48 h-8" /></div>
          <Button variant="outline" size="sm"><Download className="w-4 h-4 mr-1" />Export</Button>
        </div>
      </CardHeader>
      <CardContent>
        <Table>
          <TableHeader>
            <TableRow className="bg-slate-50">
              <TableHead className="w-10">
                <Checkbox 
                  checked={list.length > 0 && list.every(r => selectedRequests.has(r.id))}
                  onCheckedChange={(c) => toggleSelectAllList(c, list)}
                />
              </TableHead>
              <TableHead className="text-[11px]">APPLICANT</TableHead>
              <TableHead className="text-[11px]">COMPANY</TableHead>
              <TableHead className="text-[11px]">PHONE</TableHead>
              <TableHead className="text-[11px]">PORTFOLIOS</TableHead>
              <TableHead className="text-[11px]">PLAN</TableHead>
              <TableHead className="text-[11px]">BILLING</TableHead>
              <TableHead className="text-[11px]">TYPE</TableHead>
              <TableHead className="text-[11px]">SUBMITTED</TableHead>
              <TableHead className="text-[11px]">STATUS</TableHead>
              <TableHead className="text-[11px]">ACTIONS</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              <TableRow><TableCell colSpan={10} className="text-center py-8"><Loader2 className="w-5 h-5 animate-spin mx-auto" /></TableCell></TableRow>
            ) : list.length === 0 ? (
              <TableRow><TableCell colSpan={10} className="text-center py-8 text-slate-400">No requests</TableCell></TableRow>
            ) : (
              list.map(r => (
                <TableRow key={r.id}>
                  <TableCell>
                    <Checkbox 
                      checked={selectedRequests.has(r.id)}
                      onCheckedChange={(c) => toggleSelect(r.id, c)}
                    />
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center text-xs font-bold">{r.full_name?.substring(0, 2).toUpperCase()}</div>
                      <div><p className="text-sm font-medium">{r.full_name}</p><p className="text-xs text-slate-400">{r.email}</p></div>
                    </div>
                  </TableCell>
                  <TableCell className="text-sm">{r.company_name}</TableCell>
                  <TableCell className="text-sm text-slate-500">{r.phone || '—'}</TableCell>
                  <TableCell className="text-sm">{r.portfolios || r.properties_count || '—'}</TableCell>
                  <TableCell className="text-sm">
                    {r.plan ? <Badge variant="outline" className="text-[10px] capitalize bg-blue-50 text-blue-700 border-blue-100">{r.plan}</Badge> : '—'}
                  </TableCell>
                  <TableCell className="text-sm">
                    {r.billing_cycle ? <Badge variant="outline" className="text-[10px] capitalize bg-slate-50 text-slate-700 border-slate-200">{r.billing_cycle}</Badge> : '—'}
                  </TableCell>
                  <TableCell>
                    {r.request_type === 'demo'
                      ? <Badge className="bg-violet-100 text-violet-700 text-[10px] border-none font-bold">🎥 DEMO</Badge>
                      : r.request_type === 'contact' 
                        ? <Badge className="bg-indigo-100 text-indigo-700 text-[10px] border-none font-bold">✉️ CONTACT</Badge>
                        : <Badge className="bg-emerald-100 text-emerald-700 text-[10px] border-none font-bold italic">⚡ ACCESS</Badge>
                    }
                  </TableCell>
                  <TableCell className="text-sm text-slate-500">
                    {r.created_at ? new Date(r.created_at).toLocaleString('en-US', {
                      month: 'short', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit'
                    }) : '—'}
                  </TableCell>
                  <TableCell>
                    {type !== 'demo' && (
                      <Badge className={r.status === 'pending_approval' ? 'bg-amber-100 text-amber-700' : r.status === 'approved' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}>
                        {r.status?.toUpperCase()}
                      </Badge>
                    )}
                  </TableCell>
                  <TableCell>
                    <div className="flex gap-1">
                      {/* Demo & Contact — View Details only */}
                      {(r.request_type === 'contact' || r.request_type === 'demo') ? (
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button size="sm" variant="outline" className="text-xs h-7 text-blue-600 border-blue-200 hover:bg-blue-50">
                              <Mail className="w-3 h-3 mr-1" />
                              Details
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-lg">
                            <DialogHeader>
                              <DialogTitle className="flex items-center gap-2">
                                {r.request_type === 'demo' ? '🎥' : '✉️'} {r.full_name}
                              </DialogTitle>
                            </DialogHeader>
                            <div className="space-y-4 py-2">
                              <div className="grid grid-cols-2 gap-4">
                                <div>
                                  <Label className="text-xs text-slate-500">Email</Label>
                                  <p className="font-medium text-sm">{r.email}</p>
                                </div>
                                <div>
                                  <Label className="text-xs text-slate-500">Company</Label>
                                  <p className="font-medium text-sm">{r.company_name || '—'}</p>
                                </div>
                                {r.phone && (
                                  <div>
                                    <Label className="text-xs text-slate-500">Phone</Label>
                                    <p className="font-medium text-sm">{r.phone}</p>
                                  </div>
                                )}
                                {r.department && (
                                  <div>
                                    <Label className="text-xs text-slate-500">Department</Label>
                                    <p className="font-medium text-sm capitalize">{r.department}</p>
                                  </div>
                                )}
                                {r.plan && (
                                  <div>
                                    <Label className="text-xs text-slate-500">Plan</Label>
                                    <p className="font-medium text-sm capitalize">{r.plan}</p>
                                  </div>
                                )}
                                {r.request_type === 'demo' && (
                                  <div>
                                    <Label className="text-xs text-slate-500">Demo Viewed</Label>
                                    <p className={`font-semibold text-sm ${r.demo_viewed ? 'text-emerald-600' : 'text-slate-500'}`}>
                                      {r.demo_viewed ? '✓ Watched' : 'Not yet'}
                                    </p>
                                  </div>
                                )}
                                <div>
                                  <Label className="text-xs text-slate-500">Submitted</Label>
                                  <p className="font-medium text-sm">
                                    {r.created_at ? new Date(r.created_at).toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit' }) : '—'}
                                  </p>
                                </div>
                              </div>
                              {r.message && (
                                <div>
                                  <Label className="text-xs text-slate-500 mb-1 block">Message</Label>
                                  <p className="bg-slate-50 p-3 rounded-md text-sm border border-slate-100 whitespace-pre-wrap">{r.message}</p>
                                </div>
                              )}
                            </div>
                          </DialogContent>
                        </Dialog>
                      ) : (
                        /* Access requests — keep Approve / Reject / Revoke */
                        <>
                          {r.status !== 'approved' && (
                            <Button 
                              size="sm" 
                              className="text-xs h-7 bg-emerald-600 hover:bg-emerald-700 text-white border-none"
                              disabled={processingRequests.has(r.id)}
                              onClick={(e) => {
                                e.stopPropagation();
                                updateRequest.mutate({ id: r.id, approved: true });
                              }}>
                              {processingRequests.has(r.id) ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <CheckCircle2 className="w-3 h-3 mr-1" />}
                              Approve
                            </Button>
                          )}
                          {r.status !== 'rejected' && r.status !== 'approved' && (
                            <Button 
                              size="sm" 
                              variant="outline"
                              className="text-xs h-7 text-red-600 border-red-200 hover:bg-red-50"
                              disabled={processingRequests.has(r.id)}
                              onClick={(e) => {
                                e.stopPropagation();
                                updateRequest.mutate({ id: r.id, approved: false });
                              }}>
                              {processingRequests.has(r.id) ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <X className="w-3 h-3 mr-1" />}
                              Reject
                            </Button>
                          )}
                          {r.status === 'approved' && (
                            <Button 
                              size="sm" 
                              variant="outline"
                              className="text-xs h-7 text-amber-600 border-amber-200 hover:bg-amber-50"
                              disabled={processingRequests.has(r.id)}
                              onClick={(e) => {
                                e.stopPropagation();
                                revokeRequest.mutate({ id: r.id, email: r.email });
                              }}>
                              {processingRequests.has(r.id) ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Shield className="w-3 h-3 mr-1" />}
                              Revoke
                            </Button>
                          )}
                        </>
                      )}
                      <Button 
                        size="sm" 
                        variant="ghost"
                        className="text-xs h-7 px-2 text-slate-400 hover:text-red-600 hover:bg-red-50 ml-1"
                        disabled={processingRequests.has(r.id)}
                        onClick={() => {
                          if (window.confirm("Are you sure you want to permanently delete this request?")) {
                            deleteRequest.mutate(r.id);
                          }
                        }}>
                        {processingRequests.has(r.id) ? <Loader2 className="w-3 h-3 animate-spin" /> : <Trash2 className="w-3 h-3" />}
                      </Button>
                    </div>
                  </TableCell>

                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-amber-100 rounded-xl flex items-center justify-center"><Shield className="w-5 h-5 text-amber-600" /></div>
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold text-slate-900">SuperAdmin Console</h1>
              {pendingCount > 0 && <Badge className="bg-amber-100 text-amber-700">{pendingCount} pending approval</Badge>}
            </div>
            <p className="text-sm text-slate-500">Platform-wide management · CRE Platform v2.4.1 · All organizations</p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button className="bg-blue-600 hover:bg-blue-700" onClick={() => { setShowInviteModal(true); setInviteEmail(""); setInviteSuccess(false); }}><Users className="w-4 h-4 mr-2" />Invite Client</Button>
          <Button variant="outline">Settings</Button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-4">
        <Card><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">Total Organizations</p><p className="text-2xl font-bold">{orgs.length}</p><p className="text-[10px] text-emerald-500">+3 this month</p></CardContent></Card>
        <Card><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">Demo Requests</p><p className="text-2xl font-bold">{requests.filter(r => r.request_type === 'demo').length}</p><p className="text-[10px] text-violet-500">{requests.filter(r => r.request_type === 'demo' && r.demo_viewed).length} viewed</p></CardContent></Card>
        <Card><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">MRR</p><p className="text-2xl font-bold">$124,800</p><p className="text-[10px] text-emerald-500">+8.2% MoM</p></CardContent></Card>
        <Card><CardContent className="p-4"><p className="text-[10px] font-semibold text-slate-500 uppercase">Pending Approvals</p><p className="text-2xl font-bold">{pendingCount}</p><p className="text-[10px] text-slate-400">Requires review</p></CardContent></Card>
      </div>

      <Tabs defaultValue="access" onValueChange={setActiveTab}>
        <TabsList className="mb-4">
          <TabsTrigger value="access">Access Requests {pendingAccessCount > 0 && <Badge className="ml-1.5 bg-amber-500 text-white text-[10px] px-1.5">{pendingAccessCount}</Badge>}</TabsTrigger>
          <TabsTrigger value="demo">Demo Requests {pendingDemoCount > 0 && <Badge className="ml-1.5 bg-violet-500 text-white text-[10px] px-1.5">{pendingDemoCount}</Badge>}</TabsTrigger>
          <TabsTrigger value="contact">Contact Us {pendingContactCount > 0 && <Badge className="ml-1.5 bg-blue-500 text-white text-[10px] px-1.5">{pendingContactCount}</Badge>}</TabsTrigger>
          <TabsTrigger value="users">User Management</TabsTrigger>
          <TabsTrigger value="orgs">Organizations</TabsTrigger>
        </TabsList>

        <TabsContent value="access" className="mt-4">
          {renderRequestTable(accessReqs, "Access Requests", pendingAccessCount, "access")}
        </TabsContent>

        <TabsContent value="demo" className="mt-4">
          {renderRequestTable(demoReqs, "Demo Requests", pendingDemoCount, "demo")}
        </TabsContent>

        <TabsContent value="contact" className="mt-4">
          {renderRequestTable(contactReqs, "Contact Messages", pendingContactCount, "contact")}
        </TabsContent>

        <TabsContent value="users" className="mt-4">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <div>
                <CardTitle className="text-base">Platform Administrators</CardTitle>
                <p className="text-xs text-slate-400">Manage users with full administrative access to the platform.</p>
              </div>
              <Button onClick={() => setShowPlatformInviteModal(true)} size="sm" className="bg-blue-600 hover:bg-blue-700 h-8 text-xs">
                <Shield className="w-3 h-3 mr-2" /> Invite Admin
              </Button>
            </CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow className="bg-slate-50">
                    <TableHead className="text-[11px]">NAME</TableHead>
                    <TableHead className="text-[11px]">EMAIL</TableHead>
                    <TableHead className="text-[11px]">ROLE</TableHead>
                    <TableHead className="text-[11px]">ACTIONS</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {isLoadingAdmins ? (
                    <TableRow><TableCell colSpan={4} className="text-center py-8"><Loader2 className="w-5 h-5 animate-spin mx-auto text-slate-400" /></TableCell></TableRow>
                  ) : platformAdmins.length === 0 ? (
                    <TableRow><TableCell colSpan={4} className="text-center py-8 text-sm text-slate-400">No platform admins found</TableCell></TableRow>
                  ) : platformAdmins.map(admin => (
                    <TableRow key={admin.membership_id}>
                      <TableCell className="font-medium text-sm">{admin.full_name}</TableCell>
                      <TableCell className="text-sm text-slate-500">{admin.email}</TableCell>
                      <TableCell>
                        <Badge className="bg-purple-100 text-purple-700 hover:bg-purple-100 border-none text-[10px]">Super Admin</Badge>
                      </TableCell>
                      <TableCell>
                        <Button variant="ghost" size="sm" className="h-7 w-7 p-0 text-red-500 hover:text-red-600 hover:bg-red-50" disabled={admin.user_id === user.id} onClick={async () => {
                          if (!window.confirm(`Remove ${admin.email} from platform admins?`)) return;
                          try {
                            await supabase.from("memberships").delete().eq("id", admin.membership_id);
                            queryClient.invalidateQueries({ queryKey: ['platform-admins'] });
                            const { toast } = await import("sonner");
                            toast.success("Admin removed");
                          } catch (e) { console.error(e); }
                        }}>
                          <X className="w-4 h-4" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
        <TabsContent value="orgs" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Organizations & Module Access</CardTitle>
              <p className="text-xs text-slate-400">Configure which modules each organization can access. Empty = all modules (admin/legacy).</p>
            </CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow className="bg-slate-50">
                    <TableHead className="text-[11px]">ORGANIZATION & ADMIN</TableHead>
                    <TableHead className="text-[11px]">PLAN & AMOUNT</TableHead>
                    <TableHead className="text-[11px]">STATUS</TableHead>
                    <TableHead className="text-[11px]">SUBMITTED</TableHead>
                    <TableHead className="text-[11px]">ENABLED MODULES</TableHead>
                    <TableHead className="text-[11px]">ACTIONS</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {orgs.length === 0 ? (
                    <TableRow><TableCell colSpan={5} className="text-center py-8 text-sm text-slate-400">No organizations</TableCell></TableRow>
                  ) : orgs.map(org => {
                    // Determine amount based on plan
                    const planLower = (org.plan || '').toLowerCase();
                    let amount = "$0/mo";
                    if (planLower === 'starter') amount = "$249/mo";
                    if (planLower === 'professional') amount = "$499/mo";
                    if (planLower === 'enterprise') amount = "$999/mo";

                    return (
                    <TableRow key={org.id}>
                      <TableCell>
                        <div>
                          <p className="text-sm font-medium">{org.name}</p>
                          <p className="text-[10px] text-slate-500 font-mono mt-0.5">{org.admin_email || 'No admin email'}</p>
                        </div>
                      </TableCell>
                      <TableCell>
                        <div className="flex flex-col gap-0.5 items-start">
                          <Badge variant="secondary" className="text-[10px] uppercase bg-blue-50 text-blue-700 hover:bg-blue-100 font-bold tracking-tight">
                            {org.plan === 'starter' ? 'Starter' : 
                             org.plan === 'professional' ? 'Professional' : 
                             org.plan === 'enterprise' ? 'Enterprise' : 
                             (org.plan || 'Standard')}
                          </Badge>
                          <span className="text-[11px] font-semibold text-slate-700 mt-1">{amount} paid</span>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Badge className={`text-[9px] uppercase ${org.status === 'active' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{org.status}</Badge>
                      </TableCell>
                      <TableCell>
                        <span className="text-[9px] text-slate-400">
                          {org.created_at ? new Date(org.created_at).toLocaleDateString() : '—'}
                        </span>
                      </TableCell>
                      <TableCell>
                        {org.enabled_modules && org.enabled_modules.length > 0 ? (
                          <div className="flex flex-wrap gap-1">
                            {org.enabled_modules.slice(0, 4).map(m => (
                              <Badge key={m} variant="outline" className="text-[9px]">{MODULE_DEFINITIONS[m]?.label || m}</Badge>
                            ))}
                            {org.enabled_modules.length > 4 && (
                              <Badge 
                                variant="outline" 
                                className="text-[9px] cursor-pointer hover:bg-slate-100 active:scale-95 transition-all"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  setEditingOrgModules(org);
                                  setSelectedModules(org.enabled_modules || []);
                                }}
                              >
                                +{org.enabled_modules.length - 4}
                              </Badge>
                            )}
                          </div>
                        ) : (
                          <span className="text-[10px] text-slate-400 italic">None (Pending Config)</span>
                        )}
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-1">
                          {(org.status === 'pending_approval' || org.status === 'under_review' || org.status === 'onboarding') && (
                            <Button 
                              variant="default" 
                              size="sm" 
                              className="h-8 text-xs px-3 bg-emerald-600 hover:bg-emerald-700 text-white font-medium shadow-sm transition-all"
                              onClick={async (e) => {
                                e.stopPropagation();
                                console.log('[SuperAdmin] Approve clicked for org:', org.id, org.name);
                                setProcessingRequests(prev => new Set(prev).add(`org_${org.id}`));
                                try {
                                  const { data, error } = await supabase.functions.invoke('approve-organization', {
                                    body: { orgId: org.id }
                                  });

                                  if (error || data?.error) {
                                    throw new Error(error?.message || data?.error || 'Failed to approve organization');
                                  }

                                  queryClient.invalidateQueries({ queryKey: ['organizations'] });
                                  const { toast } = await import("sonner");
                                  if (data.warning) {
                                    toast.warning("Organization approved, but: " + data.warning, { duration: 6000 });
                                  } else {
                                    toast.success("Organization approved successfully! Welcome email sent.");
                                  }
                                } catch (e) {
                                  console.error(e);
                                  const { toast } = await import("sonner");
                                  toast.error(e.message || "Failed to approve organization");
                                } finally {
                                  setProcessingRequests(prev => {
                                    const next = new Set(prev);
                                    next.delete(`org_${org.id}`);
                                    return next;
                                  });
                                }
                              }}
                            >
                              {processingRequests.has(`org_${org.id}`) ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <CheckCircle2 className="w-3 h-3 mr-1" />}
                              Approve
                            </Button>
                          )}
                          <Button 
                            variant="ghost" 
                            size="sm" 
                            className="h-7 text-[10px] px-2" 
                            onClick={(e) => { 
                              e.stopPropagation();
                              console.log('[SuperAdmin] Opening module config for org:', org.id, org.name);
                              setEditingOrgModules(org); 
                              setSelectedModules(org.enabled_modules || []); 
                            }}
                          >
                            <Package className="w-3 h-3 mr-1" /> Modules
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Module Configuration Dialog */}
      <Dialog open={!!editingOrgModules} onOpenChange={() => setEditingOrgModules(null)}>
        <DialogContent className="max-w-lg max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Configure Modules — {editingOrgModules?.name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-1.5 py-2">
            <div className="flex justify-between items-center mb-3">
              <p className="text-xs text-slate-500">{selectedModules.length === 0 ? 'Unrestricted (all modules)' : `${selectedModules.length} modules enabled`}</p>
              <div className="flex gap-2">
                <Button variant="outline" size="sm" className="text-[10px] h-6" onClick={() => setSelectedModules([...ALL_MODULE_KEYS])}>Select All</Button>
                <Button variant="outline" size="sm" className="text-[10px] h-6" onClick={() => setSelectedModules([])}>Clear All</Button>
              </div>
            </div>
            {ALL_MODULE_KEYS.map(key => {
              const mod = MODULE_DEFINITIONS[key];
              const checked = selectedModules.includes(key);
              return (
                <div key={key} className="flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200">
                  <Checkbox
                    checked={checked}
                    onCheckedChange={(val) => {
                      if (val) setSelectedModules(prev => [...prev, key]);
                      else setSelectedModules(prev => prev.filter(m => m !== key));
                    }}
                  />
                  <div className="flex-1">
                    <p className="text-sm font-medium">{mod.label}</p>
                    <p className="text-[10px] text-slate-400">{mod.pages.join(', ')}</p>
                  </div>
                </div>
              );
            })}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEditingOrgModules(null)}>Cancel</Button>
            <Button
              className="bg-blue-600 hover:bg-blue-700"
              onClick={async () => {
                await OrganizationService.update(editingOrgModules.id, { enabled_modules: selectedModules });
                queryClient.invalidateQueries({ queryKey: ['organizations'] });
                const { toast } = await import("sonner");
                toast.success(`Modules updated for ${editingOrgModules.name}`);
                setEditingOrgModules(null);
              }}
            >
              Save Modules
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={showInviteModal} onOpenChange={setShowInviteModal}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Invite Client</DialogTitle>
          </DialogHeader>
          {inviteSuccess ? (
            <div className="text-center py-4">
              <CheckCircle2 className="w-10 h-10 text-emerald-500 mx-auto mb-3" />
              <p className="font-semibold text-slate-900">Invitation Sent!</p>
              <p className="text-sm text-slate-500 mt-1">An invitation email has been sent to <strong>{inviteEmail}</strong>.</p>
            </div>
          ) : (
            <div className="space-y-4 py-2">
              <div>
                <Label className="text-sm font-semibold text-slate-700">Client Email Address</Label>
                <Input
                  type="email"
                  placeholder="client@company.com"
                  value={inviteEmail}
                  onChange={e => setInviteEmail(e.target.value)}
                  className="mt-1"
                />
              </div>
              <p className="text-xs text-slate-400">The client will receive an invitation to sign in and complete onboarding.</p>
            </div>
          )}
          <DialogFooter>
            {inviteSuccess ? (
              <Button onClick={() => setShowInviteModal(false)}>Close</Button>
            ) : (
              <>
                <Button variant="outline" onClick={() => setShowInviteModal(false)}>Cancel</Button>
                <Button onClick={handleInviteClient} disabled={inviting || !inviteEmail} className="bg-blue-600 hover:bg-blue-700">
                  {inviting ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
                  Send Invitation
                </Button>
              </>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={showPlatformInviteModal} onOpenChange={setShowPlatformInviteModal}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Invite Platform Administrator</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div>
              <Label className="text-sm font-semibold text-slate-700">Email Address</Label>
              <Input
                type="email"
                placeholder="admin@cresuite.io"
                value={platformInviteEmail}
                onChange={e => setPlatformInviteEmail(e.target.value)}
                className="mt-1"
              />
            </div>
            <p className="text-xs text-amber-600 font-medium">
              Warning: This user will have unrestricted access to all organizations, users, and platform settings.
            </p>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowPlatformInviteModal(false)}>Cancel</Button>
            <Button onClick={handleInvitePlatformAdmin} disabled={platformInviting || !platformInviteEmail} className="bg-blue-600 hover:bg-blue-700">
              {platformInviting ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : null}
              Invite Admin
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from "react";
import { tenantService } from "@/services/tenantService";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import useOrgQuery from "@/hooks/useOrgQuery";
import { Link } from "react-router-dom";
import { createPageUrl } from "@/utils";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Search, Plus, Users, FileText, DollarSign, Receipt, ChevronRight } from "lucide-react";
import ModuleLink from "@/components/ModuleLink";

export default function Tenants() {
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", contact_name: "", contact_email: "", contact_phone: "", industry: "", status: "active" });
  const queryClient = useQueryClient();

  const { data: tenantEntities = [], orgId } = useOrgQuery("Tenant");
  const { data: leases = [] } = useOrgQuery("Lease");
  const { data: units = [] } = useOrgQuery("Unit");
  const { data: properties = [] } = useOrgQuery("Property");
  const { data: invoices = [] } = useOrgQuery("Invoice");

  const createMutation = useMutation({
    mutationFn: (d) => tenantService.create({ ...d, org_id: orgId || "" }),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['tenants-entity'] }); setShowAdd(false); },
  });

  // Build enriched tenant list from Tenant entity + lease data
  const tenantMap = {};
  // Start with entity-based tenants
  tenantEntities.forEach(t => {
    tenantMap[t.name] = { ...t, entityId: t.id, leases: [], units: [], properties: new Set(), totalRent: 0, invoiceCount: 0, outstandingBalance: 0 };
  });
  // Enrich from leases
  leases.forEach(l => {
    if (!l.tenant_name) return;
    if (!tenantMap[l.tenant_name]) {
      tenantMap[l.tenant_name] = { name: l.tenant_name, leases: [], units: [], properties: new Set(), totalRent: 0, invoiceCount: 0, outstandingBalance: 0 };
    }
    tenantMap[l.tenant_name].leases.push(l);
    tenantMap[l.tenant_name].totalRent += (l.annual_rent || (l.base_rent || 0) * 12 || 0);
    if (l.unit_id) tenantMap[l.tenant_name].units.push(l.unit_id);
    if (l.property_id) tenantMap[l.tenant_name].properties.add(l.property_id);
  });
  // Enrich from invoices
  invoices.forEach(inv => {
    if (tenantMap[inv.tenant_name]) {
      tenantMap[inv.tenant_name].invoiceCount++;
      if (['sent', 'partial', 'overdue'].includes(inv.status)) {
        tenantMap[inv.tenant_name].outstandingBalance += (inv.total_amount || 0) - (inv.amount_paid || 0);
      }
    }
  });

  const tenants = Object.values(tenantMap).filter(t => {
    const matchSearch = !search || t.name?.toLowerCase().includes(search.toLowerCase());
    const hasActive = t.leases?.some(l => l.status !== 'expired');
    const matchStatus = statusFilter === "all" || (statusFilter === "active" && hasActive) || (statusFilter === "expired" && !hasActive);
    return matchSearch && matchStatus;
  });

  const activeTenants = Object.values(tenantMap).filter(t => t.leases?.some(l => l.status !== 'expired'));
  const totalOutstanding = Object.values(tenantMap).reduce((s, t) => s + (t.outstandingBalance || 0), 0);

  return (
    <div className="p-4 lg:p-6 space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-slate-900">Tenants</h1>
          <p className="text-xs text-slate-500">{Object.keys(tenantMap).length} tenants · Linked to leases, units, properties, and billing</p>
        </div>
        <div className="flex gap-2">
          <ModuleLink page="Billing"><Button variant="outline" size="sm"><Receipt className="w-3.5 h-3.5 mr-1" />Billing</Button></ModuleLink>
          <Button size="sm" onClick={() => setShowAdd(true)} className="bg-blue-600 hover:bg-blue-700"><Plus className="w-3.5 h-3.5 mr-1" />Add Tenant</Button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: "Total Tenants", value: Object.keys(tenantMap).length, icon: Users, color: "bg-blue-50 text-blue-600" },
          { label: "Active Leases", value: activeTenants.length, icon: FileText, color: "bg-emerald-50 text-emerald-600" },
          { label: "Annual Rent", value: `$${(Object.values(tenantMap).reduce((s, t) => s + t.totalRent, 0) / 1000).toFixed(0)}K`, icon: DollarSign, color: "bg-amber-50 text-amber-600" },
          { label: "Outstanding", value: `$${(totalOutstanding / 1000).toFixed(0)}K`, icon: Receipt, color: "bg-red-50 text-red-600" },
        ].map((s, i) => (
          <Card key={i}><CardContent className="p-3 flex items-center gap-3">
            <div className={`w-9 h-9 rounded-lg flex items-center justify-center ${s.color}`}><s.icon className="w-4 h-4" /></div>
            <div><p className="text-[10px] font-semibold text-slate-500 uppercase">{s.label}</p><p className="text-lg font-bold">{s.value}</p></div>
          </CardContent></Card>
        ))}
      </div>

      <div className="flex gap-3 items-center">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <Input placeholder="Search tenants..." value={search} onChange={e => setSearch(e.target.value)} className="pl-9 h-8 text-sm" />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-32 h-8 text-xs"><SelectValue /></SelectTrigger>
          <SelectContent><SelectItem value="all">All</SelectItem><SelectItem value="active">Active</SelectItem><SelectItem value="expired">Expired</SelectItem></SelectContent>
        </Select>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader><TableRow className="bg-slate-50">
              <TableHead className="text-[10px]">TENANT</TableHead>
              <TableHead className="text-[10px]">INDUSTRY</TableHead>
              <TableHead className="text-[10px]">PROPERTIES</TableHead>
              <TableHead className="text-[10px]">UNITS</TableHead>
              <TableHead className="text-[10px] text-right">ANNUAL RENT</TableHead>
              <TableHead className="text-[10px] text-right">OUTSTANDING</TableHead>
              <TableHead className="text-[10px]">STATUS</TableHead>
              <TableHead className="text-[10px]">NAVIGATE</TableHead>
            </TableRow></TableHeader>
            <TableBody>
              {tenants.length === 0 ? (
                <TableRow><TableCell colSpan={8} className="text-center py-8 text-sm text-slate-400">No tenants found</TableCell></TableRow>
              ) : tenants.map((t, i) => {
                const hasActive = t.leases?.some(l => l.status !== 'expired');
                return (
                  <TableRow key={i} className="hover:bg-slate-50">
                    <TableCell>
                      <div><p className="text-sm font-medium">{t.name}</p>{t.contact_email && <p className="text-[10px] text-slate-400">{t.contact_email}</p>}</div>
                    </TableCell>
                    <TableCell className="text-xs text-slate-500">{t.industry || '—'}</TableCell>
                    <TableCell className="text-xs">{t.properties?.size || 0}</TableCell>
                    <TableCell className="text-xs">{t.units?.length || 0}</TableCell>
                    <TableCell className="text-right text-xs font-bold tabular-nums">${(t.totalRent || 0).toLocaleString()}</TableCell>
                    <TableCell className={`text-right text-xs font-bold tabular-nums ${t.outstandingBalance > 0 ? 'text-red-600' : 'text-slate-400'}`}>${(t.outstandingBalance || 0).toLocaleString()}</TableCell>
                    <TableCell><Badge className={hasActive ? 'bg-emerald-100 text-emerald-700 text-[9px]' : 'bg-slate-100 text-slate-600 text-[9px]'}>{hasActive ? 'Active' : 'Expired'}</Badge></TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <Link to={createPageUrl("TenantDetail") + `?name=${encodeURIComponent(t.name)}`}>
                          <Button variant="ghost" size="sm" className="h-6 text-[10px] px-2">Profile <ChevronRight className="w-3 h-3 ml-0.5" /></Button>
                        </Link>
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      <Dialog open={showAdd} onOpenChange={setShowAdd}>
        <DialogContent>
          <DialogHeader><DialogTitle>Add Tenant</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <div className="grid grid-cols-2 gap-3">
              <div><Label className="text-xs">Tenant Name</Label><Input value={form.name} onChange={e => setForm({...form, name: e.target.value})} /></div>
              <div><Label className="text-xs">Industry</Label><Input value={form.industry} onChange={e => setForm({...form, industry: e.target.value})} placeholder="e.g. Retail, Tech" /></div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div><Label className="text-xs">Contact Name</Label><Input value={form.contact_name} onChange={e => setForm({...form, contact_name: e.target.value})} /></div>
              <div><Label className="text-xs">Email</Label><Input value={form.contact_email} onChange={e => setForm({...form, contact_email: e.target.value})} /></div>
              <div><Label className="text-xs">Phone</Label><Input value={form.contact_phone} onChange={e => setForm({...form, contact_phone: e.target.value})} /></div>
            </div>
          </div>
          <DialogFooter><Button onClick={() => createMutation.mutate(form)} disabled={!form.name} className="bg-blue-600 hover:bg-blue-700">Create Tenant</Button></DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React from "react";
import { budgetService } from "@/services/budgetService";
import { expenseService } from "@/services/expenseService";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";
import { AlertTriangle, TrendingUp, TrendingDown, Target } from "lucide-react";

export default function Variance() {
  const { data: budgets = [] } = useQuery({
    queryKey: ['budgets'],
    queryFn: () => budgetService.list(),
  });

  const { data: expenses = [] } = useQuery({
    queryKey: ['expenses'],
    queryFn: () => expenseService.list(),
  });

  const totalBudgetedExpenses = budgets.reduce((s, b) => s + (b.total_expenses || 0), 0);
  const totalActualExpenses = expenses.reduce((s, e) => s + (e.amount || 0), 0);
  const totalBudgetedRevenue = budgets.reduce((s, b) => s + (b.total_revenue || 0), 0);
  const variance = totalBudgetedExpenses - totalActualExpenses;
  const variancePct = totalBudgetedExpenses ? ((variance / totalBudgetedExpenses) * 100) : 0;

  // Category variance
  const budgetByCategory = {};
  budgets.forEach(b => {
    (b.expense_items || []).forEach(item => {
      const cat = item.category || 'Other';
      budgetByCategory[cat] = (budgetByCategory[cat] || 0) + (item.amount || 0);
    });
  });

  const actualByCategory = {};
  expenses.forEach(e => {
    const cat = e.category || 'other';
    actualByCategory[cat] = (actualByCategory[cat] || 0) + (e.amount || 0);
  });

  const allCategories = [...new Set([...Object.keys(budgetByCategory), ...Object.keys(actualByCategory)])];
  const categoryData = allCategories.map(cat => {
    const budget = budgetByCategory[cat] || 0;
    const actual = actualByCategory[cat] || 0;
    const v = budget - actual;
    return { category: cat.replace(/_/g, ' '), budget, actual, variance: v, pct: budget ? ((v / budget) * 100).toFixed(1) : '0' };
  }).sort((a, b) => a.variance - b.variance);

  const alerts = categoryData.filter(c => c.variance < 0).slice(0, 5);

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900">Variance Engine</h1>
        <p className="text-sm text-slate-500">Budget vs actual performance analysis</p>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: "Budgeted Expenses", value: `$${(totalBudgetedExpenses/1000).toFixed(0)}K`, icon: Target, color: "bg-blue-50 text-blue-600" },
          { label: "Actual Expenses", value: `$${(totalActualExpenses/1000).toFixed(0)}K`, icon: TrendingUp, color: "bg-slate-50 text-slate-600" },
          { label: "Total Variance", value: `$${(Math.abs(variance)/1000).toFixed(0)}K`, icon: variance >= 0 ? TrendingDown : TrendingUp, color: variance >= 0 ? "bg-emerald-50 text-emerald-600" : "bg-red-50 text-red-600" },
          { label: "Over-Budget Items", value: alerts.length, icon: AlertTriangle, color: "bg-amber-50 text-amber-600" },
        ].map((s, i) => (
          <Card key={i}><CardContent className="p-4 flex items-center gap-3">
            <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${s.color}`}><s.icon className="w-5 h-5" /></div>
            <div><p className="text-[10px] font-semibold text-slate-500 uppercase">{s.label}</p><p className="text-xl font-bold">{s.value}</p></div>
          </CardContent></Card>
        ))}
      </div>

      {/* Alerts */}
      {alerts.length > 0 && (
        <Card className="border-amber-200 bg-amber-50/50">
          <CardHeader><CardTitle className="text-base flex items-center gap-2"><AlertTriangle className="w-4 h-4 text-amber-500" />Over-Budget Alerts</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-2">
              {alerts.map(a => (
                <div key={a.category} className="flex items-center justify-between bg-white rounded-lg p-3 border border-amber-200">
                  <span className="text-sm font-medium capitalize">{a.category}</span>
                  <div className="flex items-center gap-4">
                    <span className="text-xs text-slate-500">Budget: ${a.budget.toLocaleString()}</span>
                    <span className="text-xs text-slate-500">Actual: ${a.actual.toLocaleString()}</span>
                    <Badge className="bg-red-100 text-red-700">{a.pct}% over</Badge>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Chart */}
      <Card>
        <CardHeader><CardTitle className="text-base">Budget vs Actual by Category</CardTitle></CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={categoryData.slice(0, 10)} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
              <XAxis type="number" tick={{ fontSize: 10 }} tickFormatter={v => `$${(v/1000).toFixed(0)}K`} />
              <YAxis type="category" dataKey="category" width={120} tick={{ fontSize: 10 }} />
              <Tooltip formatter={v => `$${v.toLocaleString()}`} />
              <Legend />
              <Bar dataKey="budget" fill="#1a2744" name="Budget" />
              <Bar dataKey="actual" fill="#3b82f6" name="Actual" />
            </BarChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>

      {/* Table */}
      <Card>
        <CardHeader><CardTitle className="text-base">Detailed Variance</CardTitle></CardHeader>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow className="bg-slate-50">
                <TableHead className="text-[11px]">CATEGORY</TableHead>
                <TableHead className="text-[11px] text-right">BUDGET</TableHead>
                <TableHead className="text-[11px] text-right">ACTUAL</TableHead>
                <TableHead className="text-[11px] text-right">VARIANCE</TableHead>
                <TableHead className="text-[11px] text-right">% DIFF</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {categoryData.map(row => (
                <TableRow key={row.category}>
                  <TableCell className="font-medium capitalize">{row.category}</TableCell>
                  <TableCell className="text-right font-mono">${row.budget.toLocaleString()}</TableCell>
                  <TableCell className="text-right font-mono">${row.actual.toLocaleString()}</TableCell>
                  <TableCell className={`text-right font-mono ${row.variance >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                    {row.variance >= 0 ? '+' : '-'}${Math.abs(row.variance).toLocaleString()}
                  </TableCell>
                  <TableCell className="text-right">
                    <Badge className={row.variance >= 0 ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}>
                      {row.pct}%
                    </Badge>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
